def _find_folder_by_id(folder, folder_id):
    for sub in (folder.GetSubFolderList() or []):
        if sub.GetUniqueId() == folder_id:
            return sub
        found = _find_folder_by_id(sub, folder_id)
        if found:
            return found
    return None

def _resolve_folder_ids(root, folder_ids):
    """Resolve each id anywhere in the folder tree -> (folders, missing_ids).

    Callers must treat a non-empty missing list as an error before mutating,
    so an unmatched id can never turn into a silent partial delete/move.
    """
    folders, missing = [], []
    for fid in folder_ids:
        found = _find_folder_by_id(root, fid)
        if found:
            folders.append(found)
        else:
            missing.append(fid)
    return folders, missing

def _navigate_folder(mp, path):
    root = mp.GetRootFolder()
    if not path or path in ("Master", "/", ""):
        return root
    parts = path.strip("/").split("/")
    if parts[0] == "Master":
        parts = parts[1:]
    current = root
    for part in parts:
        found = False
        for sub in (current.GetSubFolderList() or []):
            if sub.GetName() == part:
                current = sub
                found = True
                break
        if not found:
            return None
    return current

def _mp_rename_folder_live(mp, p):
    """Best-effort LIVE media-pool folder rename (the API has no RenameSubFolder).

    Strategy: create a sibling with the new name, MoveClips + MoveFolders the old
    folder's contents into it, then delete the (now-empty) old folder. Clips and
    subfolders are PRESERVED. What is LOST: the folder's ColorTag, its UniqueId
    (so smart-bin/reference links to it break), and manual clip ordering.

    The lossless path is offline instead: close Resolve and use the advanced
    server's project_db rename_folder (a direct Sm2MpFolder.Name UPDATE).

    Params: path (folder to rename, e.g. "Master/Old"), new_name, plus the
    standard confirm_token gate (structural mutation).
    """
    path = p.get("path")
    new_name = p.get("new_name") or p.get("newName")
    if not path:
        return _err("path is required (folder to rename, e.g. 'Master/Old')")
    if not new_name:
        return _err("new_name is required")

    folder = _navigate_folder(mp, path)
    if not folder:
        return _err(f"Folder not found: {path}")
    if folder.GetName() == new_name:
        return _err("new_name matches the current name")

    # Parent = path minus the last segment (root when renaming a top-level folder).
    parent_path = "/".join(path.strip("/").split("/")[:-1])
    parent = _navigate_folder(mp, parent_path)
    if not parent:
        return _err(f"Parent folder not found: {parent_path or 'Master'}")
    if any(sib.GetName() == new_name for sib in (parent.GetSubFolderList() or [])):
        return _err(f"A sibling folder named '{new_name}' already exists")

    clips = folder.GetClipList() or []
    subfolders = folder.GetSubFolderList() or []

    if p.get("dry_run"):
        return _ok(would_rename=folder.GetName(), to=new_name, clips=len(clips),
                   subfolders=len(subfolders),
                   caveats=["loses ColorTag", "loses folder UniqueId (references break)",
                            "loses manual clip ordering"])

    if "confirm_token" not in p and "confirmToken" not in p and _confirm_token_required():
        return _issue_confirm_token(
            action="media_pool.rename_folder", params=p,
            preview={"operation": "media_pool.rename_folder",
                     "warning": "Live rename is delete-recreate: preserves clips + "
                                "subfolders but LOSES the folder's color tag, its "
                                "UniqueId (reference/smart-bin links break) and manual "
                                "clip ordering. For a lossless rename, close Resolve and "
                                "use the advanced project_db rename_folder instead.",
                     "folder": folder.GetName(), "new_name": new_name,
                     "clips": len(clips), "subfolders": len(subfolders)},
        )
    blocked = _consume_confirm_token(action="media_pool.rename_folder", params=p)
    if blocked:
        return blocked

    new_folder = mp.AddSubFolder(parent, new_name)
    if not new_folder:
        return _err(f"Failed to create replacement folder '{new_name}'")
    moved_clips = bool(mp.MoveClips(clips, new_folder)) if clips else True
    moved_subs = bool(mp.MoveFolders(subfolders, new_folder)) if subfolders else True
    if not (moved_clips and moved_subs):
        return _err("Failed to move contents into the renamed folder; old folder left intact",
                    state={"moved_clips": moved_clips, "moved_subfolders": moved_subs})
    deleted = bool(mp.DeleteFolders([folder]))
    return _ok(renamed=new_name, id=new_folder.GetUniqueId(),
               clips_moved=len(clips), subfolders_moved=len(subfolders),
               old_folder_deleted=deleted,
               caveats=["ColorTag not preserved", "folder UniqueId changed (references break)",
                        "manual clip ordering not preserved"])

def _build_create_clip_info_dict(
    root,
    ci: Dict[str, Any],
    index: int,
    timeline_start_frame: Optional[int] = None,
):
    """Build one MediaPool.CreateTimelineFromClips clipInfo map.

    See docs/reference/resolve_scripting_api.txt line 224: 4 keys only — mediaPoolItem,
    startFrame, endFrame, recordFrame. No trackIndex, no mediaType.
    """
    from src.domains.timeline_edit.actions import _normalize_record_frame
    if not isinstance(ci, dict):
        return None, _err(f"clip_infos[{index}] must be an object")
    cid = ci.get("clip_id") or ci.get("media_pool_item_id")
    if not cid:
        return None, _err(f"clip_infos[{index}] requires clip_id or media_pool_item_id")
    mp_item = _find_clip(root, cid)
    if not mp_item:
        return None, _err(f"clip_infos[{index}]: media pool clip not found: {cid}")
    sf = ci.get("startFrame", ci.get("start_frame"))
    ef = ci.get("endFrame", ci.get("end_frame"))
    if sf is None or ef is None:
        return None, _err(
            f"clip_infos[{index}] requires start_frame/startFrame and end_frame/endFrame "
            "(source range on the MediaPoolItem)"
        )
    rf = ci.get("recordFrame", ci.get("record_frame"))
    if rf is None:
        return None, _err(
            f"clip_infos[{index}] requires record_frame/recordFrame (timeline record frame)"
        )
    rf, rf_err = _normalize_record_frame(ci, index, timeline_start_frame)
    if rf_err:
        return None, rf_err
    return {
        "mediaPoolItem": mp_item,
        "startFrame": sf,
        "endFrame": ef,
        "recordFrame": rf,
    }, None



def _collect_media_pool_items(tl):
    """Unique Media Pool Items referenced by a timeline's items (for RelinkClips)."""
    items = []
    seen = set()
    for track_type in ("video", "audio"):
        try:
            count = int(tl.GetTrackCount(track_type) or 0)
        except Exception:
            count = 0
        for i in range(1, count + 1):
            for item in (tl.GetItemListInTrack(track_type, i) or []):
                try:
                    mpi = item.GetMediaPoolItem()
                except Exception:
                    mpi = None
                if mpi is not None and id(mpi) not in seen:
                    seen.add(id(mpi))
                    items.append(mpi)
    return items

def _resolve_timeline_create_policy(proj, p: Dict[str, Any]) -> Tuple[Optional[str], Optional[Any], Optional[Dict[str, Any]]]:
    from src.domains.timeline_conform_interchange.actions import _timeline_identity
    from src.domains.timeline_edit.actions import _unique_timeline_name
    requested_name = str(p.get("name") or "").strip()
    if not requested_name:
        return None, None, _err("name is required")
    policy = str(
        p.get("if_exists")
        or p.get("ifExists")
        or p.get("existing_policy")
        or p.get("existingPolicy")
        or "version"
    ).strip().lower()
    aliases = {
        "error": "fail",
        "existing": "reuse",
        "use_existing": "reuse",
        "unique": "version",
        "rename": "version",
        "new_version": "version",
    }
    policy = aliases.get(policy, policy)
    if policy not in {"version", "reuse", "fail"}:
        return None, None, _err("if_exists must be one of: version, reuse, fail")

    existing, existing_index = _find_timeline_by_name(proj, requested_name)
    if not existing:
        return requested_name, None, None
    if policy == "reuse":
        return requested_name, existing, _ok(
            name=existing.GetName(),
            id=existing.GetUniqueId(),
            reused_existing=True,
            if_exists=policy,
            existing_timeline=_timeline_identity(existing, existing_index),
        )
    if policy == "fail":
        err = _err(f"Timeline already exists: {requested_name}")
        err.update({
            "if_exists": policy,
            "existing_timeline": _timeline_identity(existing, existing_index),
        })
        return None, existing, err
    return _unique_timeline_name(proj, requested_name), existing, None

def _sanitize_media_path(path: Any, *, keep_filename: bool = True) -> Optional[str]:
    if not path:
        return None
    text = str(path)
    filename = os.path.basename(text.rstrip(os.sep))
    parts = [part for part in text.split(os.sep) if part]
    if text.startswith("/Volumes/") and len(parts) >= 2:
        root = f"/Volumes/{parts[1]}"
        return f"{root}/.../{filename}" if keep_filename and filename else f"{root}/..."
    if text.startswith(os.sep):
        return f"/.../{filename}" if keep_filename and filename else "/..."
    return f".../{filename}" if keep_filename and filename else "..."

def _media_path_volume_root(path: Any) -> Optional[str]:
    if not path:
        return None
    text = str(path)
    parts = [part for part in text.split(os.sep) if part]
    if text.startswith("/Volumes/") and len(parts) >= 2:
        return f"/Volumes/{parts[1]}"
    if text.startswith(os.sep) and parts:
        return os.sep + parts[0]
    return None

def _bounded_basename_matches(
    wanted: str,
    search_roots: List[str],
    p: Dict[str, Any],
) -> Tuple[List[str], Dict[str, Any]]:
    started = time.monotonic()
    # Clamp to positive: a negative max_seconds/max_files would trip the
    # >= guards on the first iteration and silently return no results (EX8).
    max_seconds = max(0.1, float(p.get("max_seconds", p.get("timeout_seconds", 20)) or 20))
    max_files = max(1, int(p.get("max_files_scanned", p.get("maxFilesScanned", 50000)) or 50000))
    max_depth_raw = p.get("max_depth", p.get("maxDepth"))
    max_depth = int(max_depth_raw) if max_depth_raw is not None else None
    all_matches = bool(p.get("all_matches", False))
    matches: List[str] = []
    files_scanned = 0
    dirs_scanned = 0
    stopped_reason = None

    for root in search_roots:
        root_depth = len(os.path.abspath(root).rstrip(os.sep).split(os.sep))
        for dirpath, dirnames, filenames in os.walk(root):
            dirs_scanned += 1
            if max_depth is not None:
                current_depth = len(os.path.abspath(dirpath).rstrip(os.sep).split(os.sep)) - root_depth
                if current_depth >= max_depth:
                    dirnames[:] = []
            files_scanned += len(filenames)
            if wanted in filenames:
                matches.append(os.path.join(dirpath, wanted))
                if not all_matches:
                    return matches, {
                        "files_scanned": files_scanned,
                        "dirs_scanned": dirs_scanned,
                        "stopped_reason": "first_match",
                    }
            if files_scanned >= max_files:
                stopped_reason = "max_files_scanned"
                break
            if time.monotonic() - started >= max_seconds:
                stopped_reason = "max_seconds"
                break
        if matches and not all_matches:
            break
        if stopped_reason:
            break

    return matches, {
        "files_scanned": files_scanned,
        "dirs_scanned": dirs_scanned,
        "stopped_reason": stopped_reason,
    }

def _ensure_timeline_tracks(tl, track_type: str, needed: int, *, audio_type: str = "stereo"):
    """Ensure a timeline exposes at least `needed` tracks of the requested type."""
    needed = max(0, int(needed or 0))
    added = 0
    try:
        current = int(tl.GetTrackCount(track_type) or 0)
    except Exception as exc:
        return {"success": False, "error": f"GetTrackCount({track_type}) failed: {exc}"}
    while current < needed:
        try:
            if track_type == "audio":
                ok = tl.AddTrack(track_type, {"audioType": audio_type})
            else:
                ok = tl.AddTrack(track_type)
        except TypeError:
            ok = tl.AddTrack(track_type)
        except Exception as exc:
            return {"success": False, "error": f"AddTrack({track_type}) failed: {exc}"}
        if not ok:
            return {"success": False, "error": f"AddTrack({track_type}) returned false at track {current + 1}"}
        added += 1
        current += 1
    return {"success": True, "existing": current - added, "added": added, "count": current}

def _set_multicam_track_names(tl, plan: Dict[str, Any]):
    results = []
    for angle in plan.get("angles") or []:
        angle_name = angle.get("angle_name") or f"Angle {angle.get('angle_index')}"
        v_index = angle.get("video_track_index")
        if v_index:
            try:
                results.append({
                    "track_type": "video",
                    "track_index": v_index,
                    "name": angle_name,
                    "success": bool(tl.SetTrackName("video", int(v_index), str(angle_name))),
                })
            except Exception as exc:
                results.append({"track_type": "video", "track_index": v_index, "success": False, "error": str(exc)})
        a_index = angle.get("audio_track_index")
        if a_index:
            try:
                results.append({
                    "track_type": "audio",
                    "track_index": a_index,
                    "name": angle_name,
                    "success": bool(tl.SetTrackName("audio", int(a_index), str(angle_name))),
                })
            except Exception as exc:
                results.append({"track_type": "audio", "track_index": a_index, "success": False, "error": str(exc)})
    return results

def _setup_multicam_timeline(proj, mp, p: Dict[str, Any]):
    from src.domains.timeline_edit.actions import _build_append_clip_info_dict, _serialize_appended_timeline_item
    root = mp.GetRootFolder()
    plan, plan_err = build_multicam_setup_plan(root, p, _find_clip)
    if plan_err:
        return plan_err
    if p.get("dry_run", False):
        return {
            **plan,
            "dry_run": True,
            "would_create_timeline": True,
            "would_append": len(plan.get("append_rows") or []),
        }

    new_tl = mp.CreateEmptyTimeline(plan["name"])
    if not new_tl:
        return _err(f"Failed to create multicam setup timeline: {plan['name']}")
    try:
        proj.SetCurrentTimeline(new_tl)
    except Exception:
        pass
    if plan.get("start_timecode"):
        try:
            new_tl.SetStartTimecode(plan["start_timecode"])
        except Exception:
            pass

    audio_type = str(p.get("audio_type", p.get("audioType", "stereo")) or "stereo")
    video_tracks = _ensure_timeline_tracks(new_tl, "video", plan.get("max_video_track", 0))
    if not video_tracks.get("success"):
        return video_tracks
    audio_tracks = _ensure_timeline_tracks(new_tl, "audio", plan.get("max_audio_track", 0), audio_type=audio_type)
    if not audio_tracks.get("success"):
        return audio_tracks
    track_names = _set_multicam_track_names(new_tl, plan)

    timeline_start = _timeline_start_frame(new_tl)
    append_infos = []
    append_rows = plan.get("append_rows") or []
    for index, row in enumerate(append_rows):
        clip_info, clip_err = _build_append_clip_info_dict(root, row, index, timeline_start)
        if clip_err:
            return clip_err
        append_infos.append(clip_info)
    appended = mp.AppendToTimeline(append_infos)
    if not appended:
        return _err("AppendToTimeline returned no items for multicam setup")

    items_out = []
    for index, item in enumerate(appended):
        item_out, item_err = _serialize_appended_timeline_item(item, index, allow_empty_timeline_item_id=True)
        if item_err:
            return item_err
        item_out["setup_row"] = append_rows[index]
        items_out.append(item_out)

    return {
        **plan,
        "dry_run": False,
        "timeline_name": new_tl.GetName(),
        "timeline_id": new_tl.GetUniqueId(),
        "items": items_out,
        "track_setup": {"video": video_tracks, "audio": audio_tracks, "names": track_names},
    }



def _metadata_clip_property_key_for_field(field: str, properties: Dict[str, Any]) -> Optional[str]:
    if field in properties:
        return field
    for alias in _METADATA_FIELD_PROPERTY_ALIASES.get(field, ()):
        if alias in properties:
            return alias
    return None

def _metadata_panel_group_for_field(field: str) -> str:
    for group, fields in _METADATA_PANEL_GROUP_FIELD_HINTS.items():
        if field in fields:
            return group
    if re.fullmatch(r"Track\s+\d+", field or ""):
        return "Audio Tracks"
    if field.startswith("Audio "):
        return "Audio"
    if field.startswith("Camera "):
        return "Camera"
    if field.startswith("VFX ") or field.startswith("S3D ") or field.startswith("3D "):
        return "Stereo3D & VFX"
    if field.endswith(" Reviewed"):
        return "Reviewed By"
    return "Unclassified"

def _metadata_panel_group_inventory(fields: List[str]) -> List[Dict[str, Any]]:
    grouped: Dict[str, List[str]] = {"All Groups": list(fields)}
    for field in fields:
        grouped.setdefault(_metadata_panel_group_for_field(field), []).append(field)

    ordered_names = list(_METADATA_PANEL_GROUP_ORDER)
    if grouped.get("Unclassified"):
        ordered_names.append("Unclassified")
    return [
        {"name": name, "field_count": len(grouped.get(name, [])), "fields": grouped.get(name, [])}
        for name in ordered_names
        if name == "All Groups" or grouped.get(name)
    ]

def _media_pool_item_probe(clip):
    metadata, metadata_error = _safe_clip_call(clip, "GetMetadata", "")
    third_party, third_party_error = _safe_clip_call(clip, "GetThirdPartyMetadata", "")
    properties, properties_error = _safe_clip_call(clip, "GetClipProperty", "")
    known_properties = {}
    for key in _MEDIA_POOL_KNOWN_CLIP_PROPERTIES:
        value, err = _safe_clip_call(clip, "GetClipProperty", key)
        known_properties[key] = {"value": value, "error": err} if err else {"value": value}

    color, color_error = _safe_clip_call(clip, "GetClipColor")
    markers, markers_error = _safe_clip_call(clip, "GetMarkers")
    flags, flags_error = _safe_clip_call(clip, "GetFlagList")
    audio_mapping, audio_mapping_error = _safe_clip_call(clip, "GetAudioMapping")
    mark, mark_error = _safe_clip_call(clip, "GetMarkInOut")

    return {
        "summary": _media_pool_item_summary(clip),
        "methods": _callable_method_names(clip, _MEDIA_POOL_ITEM_METHODS),
        "metadata": {"value": metadata, "error": metadata_error} if metadata_error else metadata,
        "third_party_metadata": (
            {"value": third_party, "error": third_party_error} if third_party_error else third_party
        ),
        "clip_properties": {"value": properties, "error": properties_error} if properties_error else properties,
        "known_clip_properties": known_properties,
        "clip_color": {"value": color, "error": color_error} if color_error else color,
        "markers": {"value": markers, "error": markers_error} if markers_error else markers,
        "flags": {"value": flags, "error": flags_error} if flags_error else flags,
        "audio_mapping": (
            {"value": audio_mapping, "error": audio_mapping_error} if audio_mapping_error else audio_mapping
        ),
        "mark_in_out": {"value": mark, "error": mark_error} if mark_error else mark,
    }

def _folder_probe(folder, depth: int = 1):
    if not folder:
        return None
    clips = []
    for clip in (folder.GetClipList() or []):
        clips.append(_media_pool_item_summary(clip))
    subfolders = []
    if depth > 0:
        for sub in (folder.GetSubFolderList() or []):
            subfolders.append(_folder_probe(sub, depth - 1))
    stale = None
    try:
        stale = bool(folder.GetIsFolderStale())
    except Exception:
        pass
    return {
        "name": folder.GetName(),
        "id": folder.GetUniqueId(),
        "stale": stale,
        "clip_count": len(clips),
        "clips": clips,
        "subfolder_count": len(subfolders),
        "subfolders": subfolders,
    }

