def _media_pool_probe(mp, p: Dict[str, Any]):
    depth = p.get("depth", 1)
    try:
        depth = max(0, min(int(depth), 4))
    except (TypeError, ValueError):
        return _err("depth must be an integer")
    root = mp.GetRootFolder()
    current = mp.GetCurrentFolder()
    selected = []
    try:
        selected = [_media_pool_item_summary(clip) for clip in (mp.GetSelectedClips() or [])]
    except Exception as exc:
        selected = [{"error": str(exc)}]
    return {
        "media_pool_id": mp.GetUniqueId(),
        "methods": _callable_method_names(mp, _MEDIA_POOL_METHODS),
        "root": _folder_probe(root, depth),
        "current_folder": _folder_probe(current, 0) if current else None,
        "selected_clips": selected,
    }

def _media_pool_probe_ingest_items(mp, p: Dict[str, Any]):
    root = mp.GetRootFolder()
    ids = p.get("clip_ids") or p.get("ids")
    selected = bool(p.get("selected", False))
    clips = []
    warnings = []
    if ids:
        if not isinstance(ids, list):
            return _err("probe_ingest_item requires clip_ids as a list")
        for clip_id in ids:
            clip = _find_clip(root, str(clip_id))
            if clip:
                clips.append(clip)
            else:
                warnings.append(f"Clip not found: {clip_id}")
    if selected:
        try:
            clips.extend(mp.GetSelectedClips() or [])
        except Exception as exc:
            warnings.append(f"GetSelectedClips failed: {exc}")
    if not clips:
        return _err("probe_ingest_item requires clip_ids or selected=True")
    out = {"items": [_media_pool_item_probe(clip) for clip in clips], "count": len(clips)}
    if warnings:
        out["warnings"] = warnings
    return out

def _imported_clip_summaries(items):
    return {
        "imported": len(items) if items else 0,
        "clips": _clip_summaries(items or []),
    }

def _format_sequence_path(pattern: str, index: int):
    try:
        return pattern % index
    except (TypeError, ValueError):
        return None

def _missing_sequence_frames(pattern: str, start: int, end: int):
    missing = []
    unformattable = False
    for index in range(start, end + 1):
        path = _format_sequence_path(pattern, index)
        if not path:
            unformattable = True
            break
        if not os.path.exists(path):
            missing.append(path)
    return missing, unformattable

def _set_current_folder_temporarily(mp, target_path: Optional[str]):
    if not target_path:
        return None, None
    target = _navigate_folder(mp, target_path)
    if not target:
        return None, _err(f"Target folder not found: {target_path}")
    previous = mp.GetCurrentFolder()
    if not mp.SetCurrentFolder(target):
        return None, _err(f"Failed to set current folder: {target_path}")
    return previous, None

def _restore_current_folder(mp, previous):
    if previous:
        try:
            mp.SetCurrentFolder(previous)
        except Exception:
            pass

def _ensure_folder_path(mp, path: str):
    if not path or path in ("Master", "/", ""):
        return mp.GetRootFolder(), None
    existing = _navigate_folder(mp, path)
    if existing:
        return existing, None
    parts = path.strip("/").split("/")
    if parts and parts[0] == "Master":
        parts = parts[1:]
    current = mp.GetRootFolder()
    built = ["Master"]
    for part in parts:
        built.append(part)
        found = None
        for sub in (current.GetSubFolderList() or []):
            if sub.GetName() == part:
                found = sub
                break
        if not found:
            found = mp.AddSubFolder(current, part)
            if not found:
                return None, _err(f"Failed to create folder: {'/'.join(built)}")
        current = found
    return current, None

def _safe_import_media(mp, p: Dict[str, Any]):
    paths, err = _string_list_param(p, "paths")
    if err:
        return err
    errors = []
    for path in paths:
        path_err = _path_error(path)
        if path_err:
            errors.append(path_err)
    if errors:
        return _err("; ".join(errors))
    if p.get("dry_run"):
        return _ok(would_import=paths, target_folder=p.get("target_folder"))
    previous, folder_err = _set_current_folder_temporarily(mp, p.get("target_folder"))
    if folder_err:
        return folder_err
    try:
        return _ok(**_imported_clip_summaries(mp.ImportMedia(paths) or []))
    finally:
        _restore_current_folder(mp, previous)

def _safe_import_sequence(mp, p: Dict[str, Any]):
    pattern = p.get("FilePath") or p.get("file_path") or p.get("pattern")
    if not pattern:
        return _err("Provide FilePath, file_path, or pattern")
    try:
        start = int(p.get("StartIndex", p.get("start_index", 1)))
        end = int(p.get("EndIndex", p.get("end_index", start)))
    except (TypeError, ValueError):
        return _err("StartIndex/EndIndex must be integers")
    if end < start:
        return _err("EndIndex must be greater than or equal to StartIndex")
    missing, unformattable = _missing_sequence_frames(pattern, start, end)
    if unformattable:
        return _err("Sequence pattern must be printf-style, e.g. frame_%03d.png")
    if missing:
        sample = missing[:5]
        suffix = "" if len(missing) <= 5 else f" (+{len(missing) - 5} more)"
        return _err(f"Missing sequence frames: {sample}{suffix}")
    info = {"FilePath": pattern, "StartIndex": start, "EndIndex": end}
    if p.get("dry_run"):
        return _ok(would_import=[info], target_folder=p.get("target_folder"))
    previous, folder_err = _set_current_folder_temporarily(mp, p.get("target_folder"))
    if folder_err:
        return folder_err
    try:
        return _ok(**_imported_clip_summaries(mp.ImportMedia([info]) or []))
    finally:
        _restore_current_folder(mp, previous)

def _safe_import_folder(mp, p: Dict[str, Any]):
    path = p.get("path")
    path_err = _path_error(path, must_be_dir=True)
    if path_err:
        return _err(path_err)
    if p.get("dry_run"):
        return _ok(would_import_folder=path, source_clips_path=p.get("source_clips_path", ""))
    return {"success": bool(mp.ImportFolderFromFile(path, p.get("source_clips_path", "")))}

def _organize_clips(mp, root, p: Dict[str, Any]):
    target_path = p.get("target_path")
    if not target_path:
        return _err("target_path is required")
    if p.get("create_missing"):
        target, target_err = _ensure_folder_path(mp, target_path)
    else:
        target = _navigate_folder(mp, target_path)
        target_err = None if target else _err(f"Target folder not found: {target_path}")
    if target_err:
        return target_err
    resolved, err = _clips_from_params(root, mp, p)
    if err:
        return err
    clips, missing = resolved
    if p.get("dry_run"):
        return _ok(target_path=target_path, clips=_clip_summaries(clips), missing=missing)
    return {"success": bool(mp.MoveClips(clips, target)), "moved": len(clips), "missing": missing}

def _copy_metadata(root, p: Dict[str, Any]):
    source = _find_clip(root, p.get("source_clip_id", ""))
    if not source:
        return _err(f"Source clip not found: {p.get('source_clip_id')}")
    target_ids = p.get("target_clip_ids")
    if not isinstance(target_ids, list) or not target_ids:
        return _err("target_clip_ids must be a non-empty list")
    metadata = source.GetMetadata("") or {}
    if p.get("keys"):
        keys = set(p["keys"])
        metadata = {key: value for key, value in metadata.items() if key in keys}
    third_party = {}
    if p.get("include_third_party", True):
        third_party = source.GetThirdPartyMetadata("") or {}
    results = []
    for target_id in target_ids:
        target = _find_clip(root, str(target_id))
        if not target:
            results.append({"clip_id": target_id, "success": False, "error": "Clip not found"})
            continue
        if p.get("dry_run"):
            results.append({"clip_id": target_id, "success": True, "metadata_keys": sorted(metadata.keys()), "third_party_keys": sorted(third_party.keys())})
            continue
        ok = bool(target.SetMetadata(metadata)) if metadata else True
        third_party_ok = True
        for key, value in third_party.items():
            third_party_ok = bool(target.SetThirdPartyMetadata(key, value)) and third_party_ok
        results.append({"clip_id": target_id, "success": ok and third_party_ok})
    return {"success": all(row.get("success") for row in results), "results": results}

def _normalize_metadata(root, mp, p: Dict[str, Any]):
    from src.domains.timeline_edit.actions import _verify_writeback
    resolved, err = _clips_from_params(root, mp, p)
    if err:
        return err
    clips, missing = resolved
    metadata = p.get("metadata") or {}
    third_party = p.get("third_party_metadata") or p.get("thirdPartyMetadata") or {}
    if not isinstance(metadata, dict) or not isinstance(third_party, dict):
        return _err("metadata and third_party_metadata must be objects")
    if not metadata and not third_party:
        return _err("Provide metadata or third_party_metadata")
    results = []
    for clip in clips:
        clip_id = _safe_media_pool_item_id(clip)
        if p.get("dry_run"):
            results.append({"clip_id": clip_id, "success": True, "metadata_keys": sorted(metadata.keys()), "third_party_keys": sorted(third_party.keys())})
            continue
        ok = bool(clip.SetMetadata(metadata)) if metadata else True
        third_party_ok = True
        for key, value in third_party.items():
            third_party_ok = bool(clip.SetThirdPartyMetadata(key, value)) and third_party_ok
        row = {"clip_id": clip_id, "success": ok and third_party_ok}
        if ok and metadata:
            silent = _verify_writeback(clip, metadata)
            if silent:
                row["success"] = False
                row["verified"] = False
                row["unpersisted"] = {silent["key"]: silent["actual"]}
                row["error"] = silent["error"]
                if silent.get("hint"):
                    row["hint"] = silent["hint"]
        results.append(row)
    return {"success": all(row.get("success") for row in results), "count": len(results), "missing": missing, "results": results}

def _probe_clip_properties(root, mp, p: Dict[str, Any]):
    resolved, err = _clips_from_params(root, mp, p)
    if err:
        return err
    clips, missing = resolved
    return {
        "count": len(clips),
        "missing": missing,
        "items": [
            {
                "summary": _media_pool_item_summary(clip),
                "properties": _safe_clip_call(clip, "GetClipProperty", "")[0],
                "known_clip_properties": _media_pool_item_probe(clip)["known_clip_properties"],
            }
            for clip in clips
        ],
    }

def _metadata_field_inventory(root, mp, p: Dict[str, Any]):
    resolved, err = _clips_from_params(root, mp, p)
    if err:
        return err
    clips, missing = resolved
    include_values = _media_analysis_bool(p.get("include_values", p.get("includeValues")), False)
    analysis_fields = list(p.get("analysis_fields") or p.get("analysisFields") or _MEDIA_ANALYSIS_DEFAULT_PUBLISH_FIELDS)
    slate_fields = ["Scene", "Shot", "Take", "Camera #", "Roll/Card"]
    optional_fields = list(p.get("optional_fields") or p.get("optionalFields") or slate_fields)

    items = []
    for clip in clips:
        metadata, metadata_error = _safe_clip_call(clip, "GetMetadata", "")
        third_party, third_party_error = _safe_clip_call(clip, "GetThirdPartyMetadata", "")
        properties, properties_error = _safe_clip_call(clip, "GetClipProperty", "")
        metadata = metadata if isinstance(metadata, dict) else {}
        third_party = third_party if isinstance(third_party, dict) else {}
        properties = properties if isinstance(properties, dict) else {}
        property_fields = list(properties.keys())
        metadata_fields = list(metadata.keys())

        def field_status(field: str) -> Dict[str, Any]:
            clip_property_key = _metadata_clip_property_key_for_field(field, properties)
            metadata_write_key = _metadata_write_field_for_field(field)
            row = {
                "field": field,
                "in_get_metadata": field in metadata,
                "in_clip_properties": clip_property_key is not None,
                "inferred_ui_group": _metadata_panel_group_for_field(field),
            }
            if metadata_write_key != field:
                row["metadata_write_key"] = metadata_write_key
            if clip_property_key:
                row["clip_property_key"] = clip_property_key
            if include_values:
                if field in metadata:
                    row["metadata_value"] = metadata.get(field)
                if clip_property_key:
                    row["clip_property_value"] = properties.get(clip_property_key)
            return row

        item = {
            "summary": _media_pool_item_summary(clip),
            "metadata": {
                "field_count": len(metadata_fields),
                "fields": metadata_fields,
            },
            "third_party_metadata": {
                "field_count": len(third_party),
                "fields": list(third_party.keys()),
            },
            "clip_properties": {
                "field_count": len(property_fields),
                "fields": property_fields,
            },
            "metadata_panel_groups": _metadata_panel_group_inventory(property_fields),
            "analysis_writeback_fields": {
                "default": [field_status(str(field)) for field in analysis_fields],
                "optional_slate": [field_status(str(field)) for field in optional_fields],
            },
        }
        if metadata_error:
            item["metadata"]["error"] = metadata_error
        if third_party_error:
            item["third_party_metadata"]["error"] = third_party_error
        if properties_error:
            item["clip_properties"]["error"] = properties_error
        if include_values:
            item["metadata"]["values"] = metadata
            item["third_party_metadata"]["values"] = third_party
            item["clip_properties"]["values"] = properties
        items.append(item)

    return {
        "success": True,
        "count": len(items),
        "missing": missing,
        "group_source": "best_effort_from_GetClipProperty_keys_and_Resolve_20_metadata_panel_labels",
        "ui_group_names": list(_METADATA_PANEL_GROUP_ORDER),
        "notes": [
            "Read-only probe: no SetMetadata or SetClipProperty calls were made.",
            "Resolve does not expose a guaranteed UI metadata-group schema through the public scripting API.",
            "Unfilled clips may return an empty GetMetadata() dict while GetClipProperty('') still exposes metadata-panel-style fields.",
            "metadata_panel_groups is an inferred grouping of the observed clip-property keys, not a Resolve-authored schema.",
        ],
        "items": items,
    }

def _safe_relink(mp, root, p: Dict[str, Any]):
    folder_path = p.get("folder_path")
    path_err = _path_error(folder_path, must_be_dir=True)
    if path_err:
        return _err(path_err)
    resolved, err = _clips_from_params(root, mp, p)
    if err:
        return err
    clips, missing = resolved
    if p.get("dry_run"):
        return _ok(folder_path=folder_path, clips=_clip_summaries(clips), missing=missing)
    return {"success": bool(mp.RelinkClips(clips, folder_path)), "count": len(clips), "missing": missing}

def _safe_unlink(mp, root, p: Dict[str, Any]):
    resolved, err = _clips_from_params(root, mp, p)
    if err:
        return err
    clips, missing = resolved
    if p.get("dry_run"):
        return _ok(clips=_clip_summaries(clips), missing=missing)
    return {"success": bool(mp.UnlinkClips(clips)), "count": len(clips), "missing": missing}

def _parse_rate(value):
    if value in (None, "", "0/0", "N/A"):
        return None
    if isinstance(value, (int, float)):
        return float(value)
    text = str(value).strip()
    if not text:
        return None
    if "/" in text:
        left, right = text.split("/", 1)
        try:
            numerator = float(left.strip())
            denominator = float(right.strip())
            return numerator / denominator if denominator else None
        except (TypeError, ValueError):
            return None
    match = re.search(r"\d+(?:\.\d+)?", text.replace(",", "."))
    return float(match.group(0)) if match else None

def _parse_int_text(value):
    if value in (None, "", "N/A"):
        return None
    if isinstance(value, bool):
        return None
    if isinstance(value, int):
        return value
    if isinstance(value, float):
        return int(value)
    match = re.search(r"\d+", str(value).replace(",", ""))
    return int(match.group(0)) if match else None

def _parse_resolution(value):
    if value in (None, "", "N/A"):
        return None
    if isinstance(value, (list, tuple)) and len(value) >= 2:
        width = _parse_int_text(value[0])
        height = _parse_int_text(value[1])
        return (width, height) if width and height else None
    match = re.search(r"(\d+)\s*[xX]\s*(\d+)", str(value))
    if not match:
        return None
    return int(match.group(1)), int(match.group(2))

def _normalize_media_token(value):
    return re.sub(r"[^a-z0-9]+", "", str(value or "").lower())

def _media_token_matches(actual, expected):
    expected_token = _normalize_media_token(expected)
    if not expected_token:
        return True
    actual_token = _normalize_media_token(actual)
    return bool(actual_token) and (
        actual_token == expected_token
        or expected_token in actual_token
        or actual_token in expected_token
    )

def _clip_media_signature(clip):
    properties, properties_error = _safe_clip_call(clip, "GetClipProperty", "")
    properties = properties if isinstance(properties, dict) else {}
    resolution = _parse_resolution(
        properties.get("Resolution")
        or properties.get("Video Resolution")
        or properties.get("Image Size")
    )
    signature = {
        "name": _safe_media_pool_item_name(clip),
        "id": _safe_media_pool_item_id(clip),
        "file_path": properties.get("File Path") or properties.get("FilePath"),
        "resolution": {"width": resolution[0], "height": resolution[1]} if resolution else None,
        "fps": _parse_rate(
            properties.get("FPS")
            or properties.get("Frame Rate")
            or properties.get("Video Frame Rate")
        ),
        "frames": _parse_int_text(
            properties.get("Frames")
            or properties.get("Frame Count")
            or properties.get("Duration Frames")
        ),
        "sample_rate": _parse_int_text(
            properties.get("Sample Rate")
            or properties.get("Audio Sample Rate")
        ),
    }
    if properties_error:
        signature["properties_error"] = properties_error
    return signature

def _probe_media_file(path: str):
    ffprobe = shutil.which("ffprobe")
    if not ffprobe:
        return {
            "success": False,
            "code": "FFPROBE_MISSING",
            "error": "ffprobe is not installed or not on PATH",
            "path": path,
        }
    try:
        proc = subprocess.run(
            [
                ffprobe,
                "-v",
                "error",
                "-show_streams",
                "-of",
                "json",
                path,
            ],
            capture_output=True,
            encoding="utf-8",
            errors="replace",
            timeout=20,
            stdin=subprocess.DEVNULL,
        )
    except subprocess.TimeoutExpired:
        return {"success": False, "code": "FFPROBE_TIMEOUT", "error": "ffprobe timed out", "path": path}
    except Exception as exc:
        return {"success": False, "code": "FFPROBE_FAILED", "error": str(exc), "path": path}
    if proc.returncode != 0:
        return {
            "success": False,
            "code": "FFPROBE_FAILED",
            "returncode": proc.returncode,
            "error": (proc.stderr or proc.stdout or "").strip(),
            "path": path,
        }
    try:
        payload = json.loads(proc.stdout or "{}")
    except json.JSONDecodeError as exc:
        return {"success": False, "code": "FFPROBE_JSON_ERROR", "error": str(exc), "path": path}
    streams = payload.get("streams") if isinstance(payload, dict) else []
    streams = streams if isinstance(streams, list) else []
    video = next((stream for stream in streams if stream.get("codec_type") == "video"), {})
    audio = next((stream for stream in streams if stream.get("codec_type") == "audio"), {})
    return {"success": True, "path": path, "video": video, "audio": audio, "stream_count": len(streams)}

def _proxy_media_signature(probe: Dict[str, Any]):
    video = probe.get("video") if isinstance(probe.get("video"), dict) else {}
    audio = probe.get("audio") if isinstance(probe.get("audio"), dict) else {}
    width = _parse_int_text(video.get("width"))
    height = _parse_int_text(video.get("height"))
    return {
        "path": probe.get("path"),
        "codec": video.get("codec_name"),
        "codec_long_name": video.get("codec_long_name"),
        "profile": video.get("profile"),
        "resolution": {"width": width, "height": height} if width and height else None,
        "fps": _parse_rate(video.get("avg_frame_rate") or video.get("r_frame_rate")),
        "frames": _parse_int_text(video.get("nb_frames") or (video.get("tags") or {}).get("NUMBER_OF_FRAMES")),
        "sample_rate": _parse_int_text(audio.get("sample_rate")),
        "channels": _parse_int_text(audio.get("channels")),
    }

def _add_proxy_resolution_mismatch(result: Dict[str, Any], source, proxy):
    """Flag resolution only when the aspect ratio differs.

    Proxies are routinely lower resolution than the source — Resolve links a
    half/quarter-res proxy happily (that is the point of proxies; verified live
    on Resolve Studio 21). Only a different aspect ratio means the file cannot
    be a proxy of this source.
    """
    if not source or not proxy:
        return
    src_w, src_h = source.get("width"), source.get("height")
    pxy_w, pxy_h = proxy.get("width"), proxy.get("height")
    if not (src_w and src_h and pxy_w and pxy_h):
        return
    if (src_w, src_h) == (pxy_w, pxy_h):
        return
    src_aspect = src_w / src_h
    pxy_aspect = pxy_w / pxy_h
    if abs(src_aspect - pxy_aspect) / src_aspect <= 0.02:
        result["warnings"].append(
            f"Proxy is a same-aspect downscale ({src_w}x{src_h} -> {pxy_w}x{pxy_h})"
        )
        return
    result["mismatches"].append({"field": "resolution", "source": source, "proxy": proxy})

def _add_proxy_mismatch(mismatches: List[Dict[str, Any]], field: str, source, proxy, *, tolerance: float = 0.0):
    if source is None or proxy is None:
        return
    if isinstance(source, (int, float)) and isinstance(proxy, (int, float)):
        if abs(float(source) - float(proxy)) <= tolerance:
            return
    elif source == proxy:
        return
    mismatches.append({"field": field, "source": source, "proxy": proxy})

def _check_proxy_media_compatibility(
    clip,
    proxy_path: str,
    *,
    expected_codec: Optional[str] = None,
    expected_profile: Optional[str] = None,
):
    source = _clip_media_signature(clip)
    probe = _probe_media_file(proxy_path)
    proxy = _proxy_media_signature(probe) if probe.get("success") else {"path": proxy_path}
    result = {
        "success": bool(probe.get("success")),
        "compatible": False,
        "source": source,
        "proxy": proxy,
        "mismatches": [],
        "warnings": [],
    }
    if not probe.get("success"):
        result["error"] = probe.get("error", "Unable to probe proxy media")
        result["code"] = probe.get("code", "FFPROBE_FAILED")
        return result

    _add_proxy_resolution_mismatch(result, source.get("resolution"), proxy.get("resolution"))
    _add_proxy_mismatch(result["mismatches"], "fps", source.get("fps"), proxy.get("fps"), tolerance=0.01)
    _add_proxy_mismatch(result["mismatches"], "frames", source.get("frames"), proxy.get("frames"), tolerance=1)
    _add_proxy_mismatch(result["mismatches"], "sample_rate", source.get("sample_rate"), proxy.get("sample_rate"))

    if expected_codec and not (
        _media_token_matches(proxy.get("codec"), expected_codec)
        or _media_token_matches(proxy.get("codec_long_name"), expected_codec)
    ):
        result["mismatches"].append({
            "field": "expected_codec",
            "expected": expected_codec,
            "proxy": proxy.get("codec") or proxy.get("codec_long_name"),
        })
    if expected_profile and not _media_token_matches(proxy.get("profile"), expected_profile):
        result["mismatches"].append({
            "field": "expected_profile",
            "expected": expected_profile,
            "proxy": proxy.get("profile"),
        })

    result["compatible"] = not result["mismatches"]
    if source.get("resolution") is None:
        result["warnings"].append("Source clip resolution was not available from GetClipProperty")
    if source.get("fps") is None:
        result["warnings"].append("Source clip FPS was not available from GetClipProperty")
    if proxy.get("frames") is None:
        result["warnings"].append("Proxy frame count was not available from ffprobe")
    return result

def _proxy_link_readback(clip):
    properties, properties_error = _safe_clip_call(clip, "GetClipProperty", "")
    properties = properties if isinstance(properties, dict) else {}
    readback = {"clip_properties": properties}
    if properties_error:
        readback["properties_error"] = properties_error
    proxy_keys = [
        "Proxy",
        "Proxy Media",
        "Proxy Media Path",
        "Proxy Path",
        "Proxy Status",
        "ProxyMediaPath",
    ]
    observed = {key: properties.get(key) for key in proxy_keys if key in properties}
    if observed:
        readback["proxy_fields"] = observed
    return readback

def _normalized_path_for_compare(path):
    if not path or not isinstance(path, str):
        return None
    return os.path.normcase(os.path.abspath(os.path.expanduser(path)))

def _proxy_readback_matches_path(readback: Dict[str, Any], proxy_path: str):
    expected = _normalized_path_for_compare(proxy_path)
    if not expected:
        return False
    proxy_fields = readback.get("proxy_fields") if isinstance(readback, dict) else {}
    proxy_fields = proxy_fields if isinstance(proxy_fields, dict) else {}
    for value in proxy_fields.values():
        if _normalized_path_for_compare(value) == expected:
            return True
    return False

def _proxy_link_journal_event(event_type: str, clip, proxy_path: str, *, success=None, verified=False, compatibility=None):
    event = {
        "type": event_type,
        "clip_id": _safe_media_pool_item_id(clip),
        "clip_name": _safe_media_pool_item_name(clip),
        "proxy_path": proxy_path,
        "success": success,
        "verified": bool(verified),
    }
    if compatibility is not None:
        event["compatible"] = bool(compatibility.get("compatible"))
        if compatibility.get("mismatches"):
            event["mismatch_fields"] = [row.get("field") for row in compatibility.get("mismatches", [])]
    return event

def _verified_operation(
    name: str,
    *,
    requested: Dict[str, Any],
    preflight: Dict[str, Any],
    execution: Dict[str, Any],
    verification_status: str,
    readback=None,
    journal_event=None,
):
    return {
        "name": name,
        "preflight": preflight,
        "requested": requested,
        "execution": execution,
        "readback": readback,
        "verified": verification_status == "readback_verified",
        "verification_status": verification_status,
        "journal_event": journal_event,
    }

def _check_proxy_media_compatibility_checked(root, p: Dict[str, Any]):
    clip = _find_clip(root, p.get("clip_id", ""))
    if not clip:
        return _err(f"Clip not found: {p.get('clip_id')}")
    proxy_path = p.get("proxy_path") or p.get("path")
    path_err = _path_error(proxy_path, must_be_file=True)
    if path_err:
        return _err(path_err)
    return _check_proxy_media_compatibility(
        clip,
        proxy_path,
        expected_codec=p.get("expected_codec") or p.get("codec"),
        expected_profile=p.get("expected_profile") or p.get("profile"),
    )

def _timeline_append_readback_snapshot(proj):
    try:
        tl = proj.GetCurrentTimeline() if proj else None
    except Exception as exc:
        return {"available": False, "error": f"GetCurrentTimeline failed: {exc}"}
    if not tl:
        return {"available": False, "error": "No current timeline"}

    timeline = {}
    try:
        timeline["name"] = tl.GetName()
    except Exception:
        timeline["name"] = None
    try:
        timeline["id"] = tl.GetUniqueId()
    except Exception:
        timeline["id"] = None

    tracks = {}
    item_count = 0
    warnings = []
    for track_type in ("video", "audio", "subtitle"):
        track_count = _timeline_track_count(tl, track_type)
        rows = []
        for track_index in range(1, track_count + 1):
            try:
                items = tl.GetItemListInTrack(track_type, track_index) or []
            except Exception as exc:
                warnings.append(f"GetItemListInTrack({track_type}, {track_index}) failed: {exc}")
                items = []
            item_count += len(items)
            rows.append({
                "track_index": track_index,
                "item_count": len(items),
                "item_ids": _timeline_item_ids(items),
            })
        tracks[track_type] = {"track_count": track_count, "tracks": rows}
    return {
        "available": True,
        "timeline": timeline,
        "item_count": item_count,
        "tracks": tracks,
        "warnings": warnings,
    }

def _append_to_timeline_with_verification(proj, mp, append_payload, requested: Dict[str, Any], expected_count: int):
    from src.domains.timeline_conform_interchange.actions import _compare_timeline_append_readback
    raw_result = {"value": None}
    before = _timeline_append_readback_snapshot(proj)

    def mutate():
        raw_result["value"] = mp.AppendToTimeline(append_payload)
        return bool(raw_result["value"])

    verification = verify_by_readback(
        mutate=mutate,
        observe=lambda: _timeline_append_readback_snapshot(proj),
        snapshot=lambda: before,
        compare=lambda before_snapshot, observed: _compare_timeline_append_readback(
            before_snapshot,
            observed,
            expected_count,
        ),
        intent=requested,
        label="media_pool.append_to_timeline",
    )
    return raw_result["value"], verification, before

def _append_to_timeline_verified_operation(requested: Dict[str, Any], verification: Dict[str, Any], before):
    success = bool(verification.get("success_raw"))
    verified = bool(verification.get("verified"))
    verification_status = "readback_verified" if verified else ("api_failed" if not success else "api_success_unverified")
    readback = {
        "before": before,
        "after": verification.get("observed"),
        "before_item_count": verification.get("before_item_count"),
        "after_item_count": verification.get("after_item_count"),
        "item_count_delta": verification.get("item_count_delta"),
        "expected_item_count_delta": verification.get("expected_item_count_delta"),
    }
    return _verified_operation(
        "media_pool.append_to_timeline",
        requested=requested,
        preflight={
            "ok": True,
            "current_timeline_available": bool(isinstance(before, dict) and before.get("available")),
            "expected_item_count_delta": requested.get("expected_count"),
        },
        execution={"api": "MediaPool.AppendToTimeline", "attempted": True, "success": success},
        readback=readback,
        verification_status=verification_status,
        journal_event={
            "type": "timeline.appended" if verified else ("timeline.append.failed" if not success else "timeline.append.unverified"),
            "success": success,
            "verified": verified,
            "expected_count": requested.get("expected_count"),
            "item_count_delta": verification.get("item_count_delta"),
        },
    )

def _link_proxy_checked(root, p: Dict[str, Any]):
    clip = _find_clip(root, p.get("clip_id", ""))
    if not clip:
        return _err(f"Clip not found: {p.get('clip_id')}")
    proxy_path = p.get("proxy_path") or p.get("path")
    path_err = _path_error(proxy_path, must_be_file=True)
    if path_err:
        return _err(path_err)
    check_compatibility = bool(
        p.get("check_compatibility")
        or p.get("require_compatible")
        or p.get("expected_codec")
        or p.get("expected_profile")
        or p.get("codec")
        or p.get("profile")
    )
    compatibility = None
    if check_compatibility:
        compatibility = _check_proxy_media_compatibility(
            clip,
            proxy_path,
            expected_codec=p.get("expected_codec") or p.get("codec"),
            expected_profile=p.get("expected_profile") or p.get("profile"),
        )
    requested = {
        "clip_id": p.get("clip_id"),
        "proxy_path": proxy_path,
        "dry_run": bool(p.get("dry_run")),
        "check_compatibility": check_compatibility,
        "require_compatible": bool(p.get("require_compatible")),
        "expected_codec": p.get("expected_codec") or p.get("codec"),
        "expected_profile": p.get("expected_profile") or p.get("profile"),
    }
    preflight = {
        "ok": True,
        "clip_found": True,
        "proxy_path_valid": True,
        "method_available": True,
        "compatibility_checked": compatibility is not None,
    }
    if compatibility is not None:
        preflight["compatible"] = bool(compatibility.get("compatible"))
    if p.get("dry_run"):
        out = _ok(clip=_media_pool_item_summary(clip), proxy_path=proxy_path)
        if compatibility is not None:
            out["compatibility"] = compatibility
        out["verified_operation"] = _verified_operation(
            "media_pool.link_proxy_checked",
            requested=requested,
            preflight=preflight,
            execution={"api": "MediaPoolItem.LinkProxyMedia", "attempted": False, "success": None},
            readback=None,
            verification_status="dry_run",
            journal_event=_proxy_link_journal_event(
                "proxy.link.preview",
                clip,
                proxy_path,
                success=None,
                verified=False,
                compatibility=compatibility,
            ),
        )
        return out
    if p.get("require_compatible") and compatibility is not None and not compatibility.get("compatible"):
        out = _err(
            "Proxy media is not compatible with the source clip; refusing LinkProxyMedia",
            code="PROXY_INCOMPATIBLE",
            category="invalid_input",
            remediation="Use a proxy with matching resolution, FPS, frame count, sample rate, and requested codec/profile.",
        )
        out["compatibility"] = compatibility
        out["verified_operation"] = _verified_operation(
            "media_pool.link_proxy_checked",
            requested=requested,
            preflight={**preflight, "ok": False},
            execution={"api": "MediaPoolItem.LinkProxyMedia", "attempted": False, "success": None},
            readback=None,
            verification_status="blocked",
            journal_event=_proxy_link_journal_event(
                "proxy.link.blocked",
                clip,
                proxy_path,
                success=False,
                verified=False,
                compatibility=compatibility,
            ),
        )
        return out
    verification = verify_by_readback(
        mutate=lambda: clip.LinkProxyMedia(proxy_path),
        observe=lambda: _proxy_link_readback(clip),
        compare=lambda _before, observed: {
            "verified": _proxy_readback_matches_path(observed, proxy_path),
        },
        intent={"clip_id": p.get("clip_id"), "proxy_path": proxy_path},
        label="media_pool.link_proxy_checked",
    )
    success = bool(verification.get("success_raw"))
    readback = verification.get("observed")
    verified = bool(verification.get("verified"))
    verification_status = "readback_verified" if verified else ("api_failed" if not success else "api_success_unverified")
    event_type = "proxy.linked" if success else "proxy.link.failed"
    out = {"success": success, "readback": readback}
    if compatibility is not None:
        out["compatibility"] = compatibility
    out["verified_operation"] = _verified_operation(
        "media_pool.link_proxy_checked",
        requested=requested,
        preflight=preflight,
        execution={"api": "MediaPoolItem.LinkProxyMedia", "attempted": True, "success": success},
        readback=readback,
        verification_status=verification_status,
        journal_event=_proxy_link_journal_event(
            event_type,
            clip,
            proxy_path,
            success=success,
            verified=verified,
            compatibility=compatibility,
        ),
    )
    return out

def _link_full_resolution_checked(root, p: Dict[str, Any]):
    clip = _find_clip(root, p.get("clip_id", ""))
    if not clip:
        return _err(f"Clip not found: {p.get('clip_id')}")
    path = p.get("path") or p.get("full_res_media_path") or p.get("fullResMediaPath")
    path_err = _path_error(path, must_be_file=True)
    if path_err:
        return _err(path_err)
    if p.get("dry_run"):
        return _ok(clip=_media_pool_item_summary(clip), path=path)
    return {"success": bool(clip.LinkFullResolutionMedia(path))}

def _set_clip_marks(root, mp, p: Dict[str, Any]):
    resolved, err = _clips_from_params(root, mp, p)
    if err:
        return err
    clips, missing = resolved
    try:
        mark_in = int(p["mark_in"])
        mark_out = int(p["mark_out"])
    except (KeyError, TypeError, ValueError):
        return _err("mark_in and mark_out must be integers")
    results = []
    for clip in clips:
        clip_id = _safe_media_pool_item_id(clip)
        if p.get("dry_run"):
            results.append({"clip_id": clip_id, "success": True, "mark_in": mark_in, "mark_out": mark_out})
            continue
        results.append({"clip_id": clip_id, "success": bool(clip.SetMarkInOut(mark_in, mark_out, p.get("type", "all")))})
    return {"success": all(row.get("success") for row in results), "count": len(results), "missing": missing, "results": results}

def _clear_clip_marks(root, mp, p: Dict[str, Any]):
    resolved, err = _clips_from_params(root, mp, p)
    if err:
        return err
    clips, missing = resolved
    results = []
    for clip in clips:
        clip_id = _safe_media_pool_item_id(clip)
        if p.get("dry_run"):
            results.append({"clip_id": clip_id, "success": True})
            continue
        results.append({"clip_id": clip_id, "success": bool(clip.ClearMarkInOut(p.get("type", "all")))})
    return {"success": all(row.get("success") for row in results), "count": len(results), "missing": missing, "results": results}

def _copy_clip_annotations(root, p: Dict[str, Any]):
    source = _find_clip(root, p.get("source_clip_id", ""))
    if not source:
        return _err(f"Source clip not found: {p.get('source_clip_id')}")
    target_ids = p.get("target_clip_ids")
    if not isinstance(target_ids, list) or not target_ids:
        return _err("target_clip_ids must be a non-empty list")
    markers = source.GetMarkers() or {}
    flags = source.GetFlagList() or []
    color = source.GetClipColor()
    include_markers = p.get("include_markers", True)
    include_flags = p.get("include_flags", True)
    include_color = p.get("include_clip_color", True)
    results = []
    for target_id in target_ids:
        target = _find_clip(root, str(target_id))
        if not target:
            results.append({"clip_id": target_id, "success": False, "error": "Clip not found"})
            continue
        if p.get("dry_run"):
            results.append({"clip_id": target_id, "success": True, "markers": len(markers), "flags": len(flags), "clip_color": color})
            continue
        ok = True
        if include_color and color:
            ok = bool(target.SetClipColor(color)) and ok
        if include_flags:
            for flag in flags:
                ok = bool(target.AddFlag(flag)) and ok
        if include_markers:
            for frame, marker in markers.items():
                custom = marker.get("customData") or marker.get("custom_data") or ""
                ok = bool(
                    target.AddMarker(
                        int(frame),
                        marker.get("color", "Blue"),
                        marker.get("name", ""),
                        marker.get("note", ""),
                        marker.get("duration", 1),
                        custom,
                    )
                ) and ok
        results.append({"clip_id": target_id, "success": ok})
    return {"success": all(row.get("success") for row in results), "results": results}

def _media_pool_boundary_report(mp, p: Dict[str, Any]):
    report = {
        "capabilities": _media_pool_ingest_capabilities(),
        "media_pool": _media_pool_probe(mp, {"depth": p.get("depth", 1)}),
    }
    if p.get("clip_ids") or p.get("selected"):
        report["items"] = _media_pool_probe_ingest_items(mp, p)
    return report

@mcp.tool()
def media_storage(action: str, params: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    """Browse storage volumes and import media into the Media Pool.

    Actions:
      get_volumes() -> {volumes}
      get_subfolders(path) -> {subfolders}
      get_files(path) -> {files}
      reveal(path) -> {success}
      import_to_pool(items) -> {imported}
        — simple: params.items is a list of absolute file/folder paths
      import_to_pool(item_infos) -> {imported}
        — positioned: params.item_infos is a list of {media, startFrame, endFrame}
          dicts per docs line 210. Mirrors MediaStorage.AddItemListToMediaPool([{itemInfo}, ...]).
      add_clip_mattes(clip_id, paths, stereo_eye?) -> {success}
      add_timeline_mattes(paths) -> {items}
    """
    p = params or {}
    r = get_resolve()
    if r is None:
        return _err("Could not connect to DaVinci Resolve. It was not running and auto-launch failed. Check that Resolve Studio is installed.")
    ms = r.GetMediaStorage()

    if action == "get_volumes":
        return {"volumes": ms.GetMountedVolumeList()}
    elif action == "get_subfolders":
        return {"subfolders": ms.GetSubFolderList(p["path"])}
    elif action == "get_files":
        return {"files": ms.GetFileList(p["path"])}
    elif action == "reveal":
        return {"success": bool(ms.RevealInStorage(p["path"]))}
    elif action == "import_to_pool":
        if p.get("item_infos") is not None:
            raw = p["item_infos"]
            if not isinstance(raw, list) or not raw:
                return _err("item_infos must be a non-empty list")
            for i, info in enumerate(raw):
                if not isinstance(info, dict):
                    return _err(f"item_infos[{i}] must be an object")
                if not info.get("media"):
                    return _err(f"item_infos[{i}] requires media (file path)")
            result = ms.AddItemListToMediaPool(raw)
        else:
            items = p.get("items")
            if not items:
                return _err("Provide items (simple) or item_infos (positioned)")
            result = ms.AddItemListToMediaPool(items)
        return {"imported": len(result) if result else 0}
    elif action == "add_clip_mattes":
        _, proj, mp, err = _get_mp()
        if err:
            return err
        clip = _find_clip(mp.GetRootFolder(), p["clip_id"])
        if not clip:
            return _err(f"Clip not found: {p['clip_id']}")
        eye = p.get("stereo_eye", "")
        return {"success": bool(ms.AddClipMattesToMediaPool(clip, p["paths"], eye))}
    elif action == "add_timeline_mattes":
        result = ms.AddTimelineMattesToMediaPool(p["paths"])
        return {"items": len(result) if result else 0}
    return _unknown(action, ["get_volumes","get_subfolders","get_files","reveal","import_to_pool","add_clip_mattes","add_timeline_mattes"])

@mcp.tool()
@_destructive_op("media_pool")
def media_pool(action: str, params: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    """Manage the Media Pool: folders, clips, timelines, import/export.

    PREFER safe_* / probe_* / *_capabilities / *_boundary_report / *_checked variants where they
    exist. Raw mutators below do not validate paths, support dry_run, or normalize errors.

    Actions:
      get_root_folder() -> {name, id}
      get_current_folder() -> {name, id}
      set_current_folder(path) -> {success}  — path like "Master/SubFolder"
      add_subfolder(name, parent_path?) -> {success, name, id}
      delete_folders(folder_ids) -> {success}
        DESTRUCTIVE. Deletes folders + every clip they contain.
      move_folders(folder_ids, target_path) -> {success}
      rename_folder(path, new_name, dry_run?, confirm_token?) -> {success, ...}
        — LIVE workaround for the missing RenameSubFolder: delete-recreate that
          PRESERVES clips + subfolders but LOSES ColorTag, the folder UniqueId
          (references break) and manual clip order. Lossless alternative: close
          Resolve and use the advanced server's project_db rename_folder.
      refresh() -> {success}
      create_timeline(name, if_exists?) -> {success, name, id}
        — if_exists: version (default), reuse, or fail
      create_timeline_from_clips(name, clip_ids, if_exists?) -> {success, name, id}
        — simple: params.clip_ids appends clips end-to-end into a new timeline
      create_timeline_from_clips(name, clip_infos, if_exists?) -> {success, name, id}
        — positioned: params.clip_infos is a list of {clip_id or media_pool_item_id,
          start_frame & end_frame (or startFrame/endFrame), record_frame/recordFrame}.
          record_frame is relative to the created timeline start frame by default;
          pass record_frame_mode="absolute" for raw Resolve recordFrame values.
      setup_multicam_timeline(name, clip_ids|angles, sync_mode?, include_audio?, dry_run?) -> {success}
        — creates a stacked multicam prep timeline: one angle per video track, optional
          matching audio tracks. Native multicam clip conversion remains a Resolve UI step.
      import_timeline(path, options?, background?) -> {success, name | job_id}
        UNSAFE. No path sandboxing. Prefer timeline.import_timeline_checked.
      delete_timelines(timeline_ids) -> {success}
        CATASTROPHIC. Deletes timelines outright.
      append_to_timeline(clip_ids) -> {success, count}
        — legacy: params.clip_ids only (appends at end / default placement)
      append_to_timeline(clip_infos) -> {success, count, items}
        — positioned: params.clip_infos is a list of {clip_id or media_pool_item_id,
          start_frame & end_frame (or startFrame/endFrame), record_frame/recordFrame,
          track_index/trackIndex (1-based), optional media_type/mediaType (1=video, 2=audio)}.
          record_frame is relative to the current timeline start frame by default;
          pass record_frame_mode="absolute" for raw Resolve recordFrame values.
          Returns timeline_item_id per item.
      import_media(paths) -> {imported}
        UNSAFE. No dry_run. Prefer safe_import_media.
        — simple: params.paths is a list of file/folder paths
      import_media(clip_infos) -> {imported}
        UNSAFE. No dry_run. Prefer safe_import_sequence.
        — image sequences: params.clip_infos is a list of
          {FilePath, StartIndex, EndIndex} dicts (PascalCase keys per Resolve docs).
          Example: [{"FilePath": "frame_%03d.dpx", "StartIndex": 1, "EndIndex": 100}]
      delete_clips(clip_ids) -> {success}
        DESTRUCTIVE. Removes clips from the Media Pool (does not touch source files).
      move_clips(clip_ids, target_path) -> {success}
      relink(clip_ids, folder_path) -> {success}
        UNSAFE. No dry_run. Prefer safe_relink.
      unlink(clip_ids) -> {success}
        UNSAFE. No dry_run. Prefer safe_unlink.
      export_metadata(path, clip_ids?) -> {success}
      get_unique_id() -> {id}
      create_stereo_clip(left_id, right_id) -> {success, name}
      auto_sync_audio(clip_ids, settings?) -> {success}
      get_selected() -> {clips}
      set_selected(clip_id) -> {success}
      get_clip_mattes(clip_id) -> {mattes}
      get_timeline_mattes(folder_path?) -> {mattes}
      delete_clip_mattes(clip_id, paths) -> {success}
      import_folder(path, source_clips_path?) -> {success}
      ingest_capabilities() -> {supported, partially_supported, unsupported}
      probe_media_pool(depth?) -> {media_pool_id, methods, root, current_folder, selected_clips}
      probe_ingest_item(clip_ids? selected?) -> {items, count}
      safe_import_media(paths, target_folder?, dry_run?) -> {success, imported, clips}
      safe_import_sequence(FilePath|file_path|pattern, StartIndex?, EndIndex?, target_folder?, dry_run?) -> {success, imported, clips}
      safe_import_folder(path, source_clips_path?, dry_run?) -> {success}
      organize_clips(clip_ids|selected, target_path, create_missing?, dry_run?) -> {success}
      copy_metadata(source_clip_id, target_clip_ids, keys?, include_third_party?, dry_run?) -> {success, results}
      normalize_metadata(clip_ids|selected, metadata?, third_party_metadata?, dry_run?) -> {success, results}
      probe_clip_properties(clip_ids|selected) -> {items, count}
      metadata_field_inventory(clip_ids|selected, include_values?) -> {items, ui_group_names}
      safe_relink(clip_ids|selected, folder_path, dry_run?) -> {success}
      safe_unlink(clip_ids|selected, dry_run?) -> {success}
      check_proxy_media_compatibility(clip_id, proxy_path|path, expected_codec?, expected_profile?) -> {compatible, mismatches}
      link_proxy_checked(clip_id, proxy_path|path, dry_run?, check_compatibility?, require_compatible?, expected_codec?, expected_profile?) -> {success}
      link_full_resolution_checked(clip_id, path|full_res_media_path, dry_run?) -> {success}
      set_clip_marks(clip_ids|selected, mark_in, mark_out, type?, dry_run?) -> {success, results}
      clear_clip_marks(clip_ids|selected, type?, dry_run?) -> {success, results}
      copy_clip_annotations(source_clip_id, target_clip_ids, include_markers?, include_flags?, include_clip_color?, dry_run?) -> {success, results}
      media_pool_boundary_report(depth?, clip_ids?, selected?) -> {capabilities, media_pool, items?}
    """
    from src.domains.timeline_edit.actions import _build_append_clip_info_dict, _serialize_appended_timeline_item
    from src.domains.audio_fairlight.actions import _normalize_auto_sync_settings
    p = params or {}
    _, proj, mp, err = _get_mp()
    if err:
        return err
    root = mp.GetRootFolder()

    if action == "get_root_folder":
        return {"name": root.GetName(), "id": root.GetUniqueId()}
    elif action == "get_current_folder":
        f = mp.GetCurrentFolder()
        return {"name": f.GetName(), "id": f.GetUniqueId()} if f else _err("No current folder")
    elif action == "set_current_folder":
        f = _navigate_folder(mp, p.get("path", ""))
        if not f:
            return _err(f"Folder not found: {p.get('path')}")
        return {"success": bool(mp.SetCurrentFolder(f))}
    elif action == "add_subfolder":
        parent = _navigate_folder(mp, p.get("parent_path", "")) or mp.GetCurrentFolder()
        f = mp.AddSubFolder(parent, p["name"])
        return _ok(name=f.GetName(), id=f.GetUniqueId()) if f else _err("Failed to create subfolder")
    elif action == "delete_folders":
        folders, missing = _resolve_folder_ids(root, p["folder_ids"])
        if missing:
            return _err(f"Folder id(s) not found: {', '.join(missing)}",
                        state={"found": len(folders), "missing": missing})
        if not folders:
            return _err("No folders found")
        if "confirm_token" not in p and "confirmToken" not in p and _confirm_token_required():
            return _issue_confirm_token(
                action="media_pool.delete_folders", params=p,
                preview={"operation": "media_pool.delete_folders",
                         "warning": "Permanently deletes folders AND every clip they contain.",
                         "folders_lost": len(folders),
                         "names": [_clip_name(f) for f in folders][:25]},
            )
        blocked = _consume_confirm_token(action="media_pool.delete_folders", params=p)
        if blocked:
            return blocked
        return {"success": bool(mp.DeleteFolders(folders))}
    elif action == "move_folders":
        target = _navigate_folder(mp, p["target_path"])
        if not target:
            return _err(f"Target folder not found: {p['target_path']}")
        folders, missing = _resolve_folder_ids(root, p["folder_ids"])
        if missing:
            return _err(f"Folder id(s) not found: {', '.join(missing)}",
                        state={"found": len(folders), "missing": missing})
        if not folders:
            return _err("No folders found")
        return {"success": bool(mp.MoveFolders(folders, target))}
    elif action == "rename_folder":
        return _mp_rename_folder_live(mp, p)
    elif action == "refresh":
        return {"success": bool(mp.RefreshFolders())}
    elif action == "create_timeline":
        create_name, existing, policy_result = _resolve_timeline_create_policy(proj, p)
        if policy_result:
            return policy_result
        tl = mp.CreateEmptyTimeline(create_name)
        return _ok(
            name=tl.GetName(),
            id=tl.GetUniqueId(),
            requested_name=p.get("name"),
            created_new=True,
            versioned_name=bool(existing and create_name != p.get("name")),
        ) if tl else _err("Failed to create timeline")
    elif action == "create_timeline_from_clips":
        create_name, existing, policy_result = _resolve_timeline_create_policy(proj, p)
        if policy_result:
            return policy_result
        if p.get("clip_infos") is not None:
            raw = p["clip_infos"]
            if not isinstance(raw, list):
                return _err("clip_infos must be a list")
            if not raw:
                return _err("clip_infos must be a non-empty list")
            for i, ci in enumerate(raw):
                _, row_err = _build_create_clip_info_dict(root, ci, i)
                if row_err:
                    return row_err
            tl = mp.CreateEmptyTimeline(create_name)
            if not tl:
                return _err("Failed to create timeline from clip_infos")
            try:
                proj.SetCurrentTimeline(tl)
            except Exception:
                pass
            timeline_start = _timeline_start_frame(tl)
            built = []
            for i, ci in enumerate(raw):
                append_ci = dict(ci)
                append_ci.setdefault("track_index", append_ci.get("trackIndex", 1))
                row, row_err = _build_append_clip_info_dict(root, append_ci, i, timeline_start)
                if row_err:
                    return row_err
                built.append(row)
            appended = mp.AppendToTimeline(built)
            if not appended:
                return _err("Failed to append clip_infos to created timeline")
            return _ok(
                name=tl.GetName(),
                id=tl.GetUniqueId(),
                requested_name=p.get("name"),
                created_new=True,
                versioned_name=bool(existing and create_name != p.get("name")),
            )
        clip_ids = p.get("clip_ids")
        if not clip_ids:
            return _err("Provide clip_ids (simple) or clip_infos (positioned)")
        clips = [_find_clip(root, cid) for cid in clip_ids]
        clips = [c for c in clips if c]
        if not clips:
            return _err("No valid clips found")
        tl = mp.CreateTimelineFromClips(create_name, clips)
        return _ok(
            name=tl.GetName(),
            id=tl.GetUniqueId(),
            requested_name=p.get("name"),
            created_new=True,
            versioned_name=bool(existing and create_name != p.get("name")),
        ) if tl else _err("Failed to create timeline")
    elif action == "setup_multicam_timeline":
        return _setup_multicam_timeline(proj, mp, p)
    elif action == "import_timeline":
        # Whitelist options to the documented keys; Resolve silently ignores
        # unknown keys, so a typo would be dropped with no signal (P1 #4).
        options, ignored_opts = _filter_to_keys(p.get("options", {}), _IMPORT_TIMELINE_OPTION_KEYS)

        def _work():
            tl = mp.ImportTimelineFromFile(p["path"], options)
            if not tl:
                return _err("Failed to import timeline")
            result = _ok(name=tl.GetName())
            if ignored_opts:
                result["ignored_options"] = ignored_opts
            return result

        return _run_maybe_background("media_pool.import_timeline", p, _work)
    elif action == "delete_timelines":
        count = proj.GetTimelineCount()
        timelines = []
        for i in range(1, count + 1):
            tl = proj.GetTimelineByIndex(i)
            if tl and tl.GetUniqueId() in p["timeline_ids"]:
                timelines.append(tl)
        if not timelines:
            return _err("No timelines found")
        if "confirm_token" not in p and "confirmToken" not in p and _confirm_token_required():
            return _issue_confirm_token(
                action="media_pool.delete_timelines", params=p,
                preview={"operation": "media_pool.delete_timelines",
                         "warning": "Permanently deletes timelines.",
                         "timelines_lost": len(timelines),
                         "names": [t.GetName() for t in timelines][:25]},
            )
        blocked = _consume_confirm_token(action="media_pool.delete_timelines", params=p)
        if blocked:
            return blocked
        # Read-back: DeleteTimelines' bool is unreliable; verify by the project's
        # timeline count dropping (P2).
        before_n = proj.GetTimelineCount()
        raw = bool(mp.DeleteTimelines(timelines))
        after_n = proj.GetTimelineCount()
        return {"success": raw, "verified": after_n < before_n,
                "timelines_before": before_n, "timelines_after": after_n}
    elif action == "append_to_timeline":
        if p.get("clip_infos") is not None:
            raw = p["clip_infos"]
            if not isinstance(raw, list):
                return _err("clip_infos must be a list")
            if not raw:
                return _err("clip_infos must be a non-empty list")
            timeline_start = _timeline_start_frame(proj.GetCurrentTimeline())
            built = []
            for i, ci in enumerate(raw):
                row, row_err = _build_append_clip_info_dict(root, ci, i, timeline_start)
                if row_err:
                    return row_err
                built.append(row)
            requested = {
                "mode": "clip_infos",
                "clip_info_count": len(raw),
                "expected_count": len(built),
            }
            result, verification, before = _append_to_timeline_with_verification(
                proj,
                mp,
                built,
                requested,
                len(built),
            )
            if not result:
                return _err("Failed to append clip_infos to timeline")
            items_out = []
            for i, item in enumerate(result):
                item_out, item_err = _serialize_appended_timeline_item(item, i)
                if item_err:
                    return item_err
                items_out.append(item_out)
            out = _ok(count=len(result), items=items_out)
            out["verified_operation"] = _append_to_timeline_verified_operation(
                requested,
                verification,
                before,
            )
            return out
        clip_ids = p.get("clip_ids")
        if not clip_ids:
            return _err("Provide clip_ids (simple append) or clip_infos (positioned append)")
        clips = [_find_clip(root, cid) for cid in clip_ids]
        clips = [c for c in clips if c]
        requested = {
            "mode": "clip_ids",
            "clip_ids": list(clip_ids),
            "resolved_clip_count": len(clips),
            "expected_count": len(clips),
        }
        result, verification, before = _append_to_timeline_with_verification(
            proj,
            mp,
            clips,
            requested,
            len(clips),
        )
        out = _ok(count=len(result) if result else 0)
        out["verified_operation"] = _append_to_timeline_verified_operation(
            requested,
            verification,
            before,
        )
        return out
    elif action == "import_media":
        if p.get("clip_infos") is not None:
            raw = p["clip_infos"]
            if not isinstance(raw, list) or not raw:
                return _err("clip_infos must be a non-empty list")
            for i, ci in enumerate(raw):
                if not isinstance(ci, dict):
                    return _err(f"clip_infos[{i}] must be an object")
                if not ci.get("FilePath"):
                    return _err(f"clip_infos[{i}] requires FilePath")
            result = mp.ImportMedia(raw)
        else:
            paths = p.get("paths")
            if not paths:
                return _err("Provide paths (simple) or clip_infos (image sequences)")
            result = mp.ImportMedia(paths)
        return {"imported": len(result) if result else 0}
    elif action == "delete_clips":
        clips = [_find_clip(root, cid) for cid in p["clip_ids"]]
        clips = [c for c in clips if c]
        if not clips:
            return _err("No clips found")
        if "confirm_token" not in p and "confirmToken" not in p and _confirm_token_required():
            return _issue_confirm_token(
                action="media_pool.delete_clips", params=p,
                preview={"operation": "media_pool.delete_clips",
                         "warning": "Permanently deletes Media Pool clips.",
                         "clips_lost": len(clips),
                         "names": [_clip_name(c) for c in clips][:25]},
            )
        blocked = _consume_confirm_token(action="media_pool.delete_clips", params=p)
        if blocked:
            return blocked
        return {"success": bool(mp.DeleteClips(clips))}
    elif action == "move_clips":
        target = _navigate_folder(mp, p["target_path"])
        if not target:
            return _err(f"Target folder not found: {p['target_path']}")
        clips = [_find_clip(root, cid) for cid in p["clip_ids"]]
        clips = [c for c in clips if c]
        return {"success": bool(mp.MoveClips(clips, target))}
    elif action == "relink":
        clips = [_find_clip(root, cid) for cid in p["clip_ids"]]
        clips = [c for c in clips if c]
        return {"success": bool(mp.RelinkClips(clips, p["folder_path"]))}
    elif action == "unlink":
        clips = [_find_clip(root, cid) for cid in p["clip_ids"]]
        clips = [c for c in clips if c]
        return {"success": bool(mp.UnlinkClips(clips))}
    elif action == "export_metadata":
        clip_ids = p.get("clip_ids")
        if clip_ids:
            clips = [_find_clip(root, cid) for cid in clip_ids]
            clips = [c for c in clips if c]
            return {"success": bool(mp.ExportMetadata(p["path"], clips))}
        return {"success": bool(mp.ExportMetadata(p["path"]))}
    elif action == "get_unique_id":
        return {"id": mp.GetUniqueId()}
    elif action == "create_stereo_clip":
        left = _find_clip(root, p["left_id"])
        right = _find_clip(root, p["right_id"])
        if not left or not right:
            return _err("Left or right clip not found")
        result = mp.CreateStereoClip(left, right)
        return _ok(name=result.GetName()) if result else _err("Failed to create stereo clip")
    elif action == "auto_sync_audio":
        clips = [_find_clip(root, cid) for cid in p["clip_ids"]]
        clips = [c for c in clips if c]
        # Normalize string settings into live AUDIO_SYNC_* enum keys; passing raw
        # human-readable keys makes AutoSyncAudio silently reject the call.
        settings, ignored = _normalize_auto_sync_settings(dict(p.get("settings") or {}), get_resolve())
        result = {"success": bool(mp.AutoSyncAudio(clips, settings))}
        if ignored:
            result["ignored_settings"] = ignored
        return result
    elif action == "get_selected":
        sel = mp.GetSelectedClips()
        if not sel:
            return {"clips": []}
        return {"clips": [{"name": c.GetName(), "id": c.GetUniqueId()} for c in sel]}
    elif action == "set_selected":
        clip = _find_clip(root, p["clip_id"])
        return {"success": bool(mp.SetSelectedClip(clip))} if clip else _err("Clip not found")
    elif action == "get_clip_mattes":
        clip = _find_clip(root, p["clip_id"])
        return {"mattes": mp.GetClipMatteList(clip)} if clip else _err("Clip not found")
    elif action == "get_timeline_mattes":
        folder = _navigate_folder(mp, p.get("folder_path", "")) or mp.GetCurrentFolder()
        result = mp.GetTimelineMatteList(folder)
        return {"mattes": len(result) if result else 0}
    elif action == "delete_clip_mattes":
        clip = _find_clip(root, p["clip_id"])
        if not clip:
            return _err("Clip not found")
        return {"success": bool(mp.DeleteClipMattes(clip, p["paths"]))}
    elif action == "import_folder":
        if not p.get("path"):
            return _err("import_folder requires path")
        return {"success": bool(mp.ImportFolderFromFile(p["path"], p.get("source_clips_path", "")))}
    elif action == "ingest_capabilities":
        return _media_pool_ingest_capabilities()
    elif action == "probe_media_pool":
        return _media_pool_probe(mp, p)
    elif action == "probe_ingest_item":
        return _media_pool_probe_ingest_items(mp, p)
    elif action == "safe_import_media":
        return _safe_import_media(mp, p)
    elif action == "safe_import_sequence":
        return _safe_import_sequence(mp, p)
    elif action == "safe_import_folder":
        return _safe_import_folder(mp, p)
    elif action == "organize_clips":
        return _organize_clips(mp, root, p)
    elif action == "copy_metadata":
        return _copy_metadata(root, p)
    elif action == "normalize_metadata":
        return _normalize_metadata(root, mp, p)
    elif action == "probe_clip_properties":
        return _probe_clip_properties(root, mp, p)
    elif action == "metadata_field_inventory":
        return _metadata_field_inventory(root, mp, p)
    elif action == "safe_relink":
        return _safe_relink(mp, root, p)
    elif action == "safe_unlink":
        return _safe_unlink(mp, root, p)
    elif action == "check_proxy_media_compatibility":
        return _check_proxy_media_compatibility_checked(root, p)
    elif action == "link_proxy_checked":
        return _link_proxy_checked(root, p)
    elif action == "link_full_resolution_checked":
        return _link_full_resolution_checked(root, p)
    elif action == "set_clip_marks":
        return _set_clip_marks(root, mp, p)
    elif action == "clear_clip_marks":
        return _clear_clip_marks(root, mp, p)
    elif action == "copy_clip_annotations":
        return _copy_clip_annotations(root, p)
    elif action == "media_pool_boundary_report":
        return _media_pool_boundary_report(mp, p)
    return _unknown(action, ["get_root_folder","get_current_folder","set_current_folder","add_subfolder","delete_folders","move_folders","rename_folder","refresh","create_timeline","create_timeline_from_clips","import_timeline","delete_timelines","append_to_timeline","import_media","delete_clips","move_clips","relink","unlink","export_metadata","get_unique_id","create_stereo_clip","auto_sync_audio","get_selected","set_selected","get_clip_mattes","get_timeline_mattes","delete_clip_mattes","import_folder",*_MEDIA_POOL_KERNEL_ACTIONS])

@mcp.tool()
def folder(action: str, params: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    """Operations on Media Pool folders.

    Actions:
      get_clips(path?) -> {clips}  — path like "Master/SubFolder", omit for current
      get_name(path?) -> {name}
      get_subfolders(path?) -> {subfolders}
      is_stale(path?) -> {stale}
      get_unique_id(path?) -> {id}
      export(path?, export_path) -> {success}
      transcribe_audio(path?, use_speaker_detection?, background?) -> {success | job_id}  — use_speaker_detection is Resolve 21+; background=true returns a job_id (poll resolve_control job_status)
      clear_transcription(path?) -> {success}
      perform_audio_classification(path?) -> {success}  — Resolve 21+
      clear_audio_classification(path?) -> {success}  — Resolve 21+
      analyze_for_intellisearch(path?, identify_faces?, is_better_mode?) -> {success}  — Resolve 21+, AI IntelliSearch Extra
      analyze_for_slate(path?, marker_color?) -> {success}  — Resolve 21+, AI Slate ID Extra
      remove_motion_blur(path?, deblur_option?) -> {success, created}  — Resolve 21+; renders NEW media (confirm-gated)
    """
    p = params or {}
    _, _, mp, err = _get_mp()
    if err:
        return err

    folder_path = p.get("path", "")
    f = _navigate_folder(mp, folder_path) if folder_path else mp.GetCurrentFolder()
    if not f:
        return _err(f"Folder not found: {folder_path}")

    if action == "get_clips":
        clips = f.GetClipList() or []
        return {"clips": [{"name": c.GetName(), "id": c.GetUniqueId()} for c in clips]}
    elif action == "get_name":
        return {"name": f.GetName()}
    elif action == "get_subfolders":
        subs = f.GetSubFolderList() or []
        return {"subfolders": [{"name": s.GetName(), "id": s.GetUniqueId()} for s in subs]}
    elif action == "is_stale":
        return {"stale": bool(f.GetIsFolderStale())}
    elif action == "get_unique_id":
        return {"id": f.GetUniqueId()}
    elif action == "export":
        return {"success": bool(f.Export(p["export_path"]))}
    elif action == "transcribe_audio":
        usd = _first_param(p, "use_speaker_detection", "useSpeakerDetection")
        if usd is None:
            return _run_maybe_background(
                "folder.transcribe_audio", p, lambda: {"success": bool(f.TranscribeAudio())}
            )
        return _run_maybe_background(
            "folder.transcribe_audio", p, lambda: {"success": bool(f.TranscribeAudio(bool(usd)))}
        )
    elif action == "clear_transcription":
        return {"success": bool(f.ClearTranscription())}
    elif action == "perform_audio_classification":
        missing = _requires_method(f, "PerformAudioClassification", "21.0")
        if missing:
            return missing
        with _ai_ledger_timed("perform_audio_classification") as _rec:
            ok = bool(f.PerformAudioClassification())
            _rec.success = ok
        return {"success": ok}
    elif action == "clear_audio_classification":
        missing = _requires_method(f, "ClearAudioClassification", "21.0")
        if missing:
            return missing
        with _ai_ledger_timed("clear_audio_classification") as _rec:
            ok = bool(f.ClearAudioClassification())
            _rec.success = ok
        return {"success": ok}
    elif action == "analyze_for_intellisearch":
        missing = _requires_method(f, "AnalyzeForIntellisearch", "21.0")
        if missing:
            return missing
        identify_faces = bool(_first_param(p, "identify_faces", "identifyFaces", default=False))
        is_better_mode = bool(_first_param(p, "is_better_mode", "isBetterMode", default=False))
        with _ai_ledger_timed("analyze_for_intellisearch") as _rec:
            ok = bool(f.AnalyzeForIntellisearch(identify_faces, is_better_mode))
            _rec.success = ok
        return {"success": ok}
    elif action == "analyze_for_slate":
        missing = _requires_method(f, "AnalyzeForSlate", "21.0")
        if missing:
            return missing
        marker_color = _first_param(p, "marker_color", "markerColor", default="Blue")
        if marker_color not in _MARKER_COLORS:
            return _err(f"Invalid marker_color {marker_color!r}. Valid colors: {', '.join(_MARKER_COLORS)}")
        with _ai_ledger_timed("analyze_for_slate") as _rec:
            ok = bool(f.AnalyzeForSlate(marker_color))
            _rec.success = ok
        return {"success": ok}
    elif action == "remove_motion_blur":
        missing = _requires_method(f, "RemoveMotionBlur", "21.0")
        if missing:
            return missing
        deblur = _first_param(p, "deblur_option", "deblurOption", default=None) or {}
        gate = _ai_governance_gate("remove_motion_blur", p)
        if gate:
            return gate
        if "confirm_token" not in p and "confirmToken" not in p and _confirm_token_required():
            return _issue_confirm_token(
                action="folder.remove_motion_blur",
                params=p,
                preview={
                    "operation": "folder.remove_motion_blur",
                    "warning": "Renders NEW deblurred media files for clips in the folder; source media is not modified.",
                    "folder": f.GetName(),
                    "deblur_option": deblur,
                    "governance": _ai_governance_check("remove_motion_blur"),
                },
            )
        blocked = _consume_confirm_token(action="folder.remove_motion_blur", params=p)
        if blocked:
            return blocked
        with _ai_ledger_timed("remove_motion_blur") as _rec:
            result = f.RemoveMotionBlur(deblur)
            _rec.success = bool(result)
            created = []
            total_bytes = 0
            for pair in (result or []):
                try:
                    # Live-verified on 21.0.2.4 (issue #20): Folder.RemoveMotionBlur
                    # returns [{1: origMediaPoolItem, 2: newMediaPoolItem}, ...] — an
                    # int-keyed dict per pair, not a 2-tuple. Unpacking a dict yields
                    # its keys (1, 2), not the items, so plain `orig, new = pair`
                    # silently produced garbage here. See core/api_truth.py.
                    orig, new = (pair[1], pair[2]) if isinstance(pair, dict) else pair
                    path, nbytes = _clip_file_size(new)
                    if nbytes:
                        total_bytes += nbytes
                    created.append({"original": orig.GetName(), "new": new.GetName(),
                                    "new_id": new.GetUniqueId(), "output_path": path, "output_bytes": nbytes})
                except Exception:
                    continue
            # Folder deblur creates many files; record the first path + summed bytes.
            if created:
                _rec.output_path = created[0].get("output_path")
                _rec.output_bytes = total_bytes or None
        return {"success": bool(result), "created": created}
    return _unknown(action, ["get_clips","get_name","get_subfolders","is_stale","get_unique_id","export","transcribe_audio","clear_transcription","perform_audio_classification","clear_audio_classification","analyze_for_intellisearch","analyze_for_slate","remove_motion_blur"])

@mcp.tool()
def media_pool_item(action: str, params: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    """Operations on a media pool clip. Identify clip by clip_id.

    Actions:
      get_name(clip_id) -> {name}
      get_metadata(clip_id, key?) -> {metadata}
      set_metadata(clip_id, key, value) OR set_metadata(clip_id, metadata) -> {success}
      get_third_party_metadata(clip_id, key?) -> {metadata}
      set_third_party_metadata(clip_id, key, value) -> {success}
      get_media_id(clip_id) -> {media_id}
      get_clip_property(clip_id, key?) -> {properties, cloud_sync_status?}  — cloud_sync_status is a friendly label for the "Cloud Sync" enum (present when key is '' or 'Cloud Sync')
      set_clip_property(clip_id, key, value) -> {success}
      set_clip_super_scale(clip_id, mode, sharpness?, noise_reduction?) -> {success, verified, mode, enhanced}  — Resolve 21+; mode 1=none,2/3/4=2x/3x/4x. sharpness+noise_reduction (both required together, [0.0,1.0]) select '2x Enhanced' at mode=2
      get_clip_color(clip_id) -> {color}
      set_clip_color(clip_id, color) -> {success}
      clear_clip_color(clip_id) -> {success}
      link_proxy(clip_id, proxy_path) -> {success}
      unlink_proxy(clip_id) -> {success}
      replace_clip(clip_id, path) -> {success}
      set_name(clip_id, name) -> {success}
      link_full_resolution_media(clip_id, path) -> {success}
      monitor_growing_file(clip_id) -> {success}
      replace_clip_preserve_sub_clip(clip_id, path) -> {success}
      get_unique_id(clip_id) -> {id}
      transcribe_audio(clip_id, use_speaker_detection?, background?) -> {success | job_id}  — use_speaker_detection is Resolve 21+; background=true returns a job_id (poll resolve_control job_status)
      clear_transcription(clip_id) -> {success}
      get_transcription(clip_id) -> {text, truncated, status, has_transcription}
        Read a clip's transcription. `truncated` flags when Resolve's preview
        property cut the text off (the full transcript is longer). Clip-level and
        separate from the timeline subtitle transcript (timeline.get_transcript)
        that propose_cuts uses.
      extract_frames(clip_id, timestamps, output_dir?) -> {frame_paths, output_dir, count, errors}
        Extract still JPEGs from the clip's source at the given timestamps (seconds)
        via ffmpeg. Source-safe: reads source, writes only to a scratch dir.
      perform_audio_classification(clip_id) -> {success}  — Resolve 21+
      clear_audio_classification(clip_id) -> {success}  — Resolve 21+
      analyze_for_intellisearch(clip_id, identify_faces?, is_better_mode?) -> {success}  — Resolve 21+, AI IntelliSearch Extra
      analyze_for_slate(clip_id, marker_color?) -> {success}  — Resolve 21+, AI Slate ID Extra
      remove_motion_blur(clip_id, deblur_option?) -> {success, new, new_id}  — Resolve 21+; renders NEW media (confirm-gated)
      get_audio_mapping(clip_id) -> {mapping}
      get_mark_in_out(clip_id) -> {mark}
      set_mark_in_out(clip_id, mark_in, mark_out, type?) -> {success}
      clear_mark_in_out(clip_id, type?) -> {success}
      open_in_viewer(clip_id, page?, mark_in_seconds?, mark_out_seconds?, clear_marks?) -> {success, clip_id, clip_name, folder_name, page, mark_set}
        — Switches to Media page (default) and selects the clip in the bin.
          Resolve auto-loads the selected clip into the source viewer on Media page.
          Optional: pre-set Mark In/Out on the clip so a shot's time range is
          highlighted when it loads.
          NOTE: Source-viewer auto-load is undocumented in the Scripting API;
          verified empirically on Resolve Studio 20.3.2.9. If BMD changes the
          behavior the clip will still be selected — editor double-clicks to load.
    """
    from src.domains.color_grade.actions import _extract_clip_frames
    from src.domains.timeline_edit.actions import _verify_clip_property_writeback, _verify_writeback
    p = params or {}
    _, _, mp, err = _get_mp()
    if err:
        return err

    # open_in_viewer needs (clip, parent_folder) to set the bin to the right folder.
    # Other actions just need the clip.
    if action == "open_in_viewer":
        clip, parent = _find_clip_with_parent(mp.GetRootFolder(), p.get("clip_id", ""))
        if not clip:
            return _err(f"Clip not found: {p.get('clip_id')}")
        page = (p.get("page") or "media").strip().lower()
        if page not in ("media", "cut", "edit"):
            return _err(f"Unsupported page for open_in_viewer: {page!r}. Use 'media' (recommended), 'cut', or 'edit'.")
        resolve_obj = get_resolve()
        if resolve_obj is None:
            return _err("Not connected to DaVinci Resolve. Is Resolve running?")
        if not resolve_obj.OpenPage(page):
            return _err(f"Failed to switch to {page} page")

        # V2 P14+B4: Optional mark in/out so a shot's time range is pre-highlighted
        # when the clip loads in source viewer. Caller passes seconds; we convert
        # to frames using the clip's fps from properties.
        mark_set: Optional[Dict[str, Any]] = None
        if p.get("clear_marks") or p.get("clearMarks"):
            try:
                clip.ClearMarkInOut(p.get("mark_type") or "all")
                mark_set = {"cleared": True}
            except Exception as exc:
                mark_set = {"cleared": False, "error": str(exc)}
        else:
            mark_in_s = p.get("mark_in_seconds") if p.get("mark_in_seconds") is not None else p.get("markInSeconds")
            mark_out_s = p.get("mark_out_seconds") if p.get("mark_out_seconds") is not None else p.get("markOutSeconds")
            if mark_in_s is not None or mark_out_s is not None:
                # Resolve fps from clip properties; fall back to 24 if not readable.
                try:
                    fps_str = clip.GetClipProperty("FPS") or clip.GetClipProperty("Frame Rate") or "24"
                    fps = float(str(fps_str).split()[0])
                    if fps <= 0:
                        fps = 24.0
                except Exception:
                    fps = 24.0
                in_frame = int(round(float(mark_in_s) * fps)) if mark_in_s is not None else 0
                out_frame = int(round(float(mark_out_s) * fps)) if mark_out_s is not None else None
                if out_frame is None:
                    # No out → caller wants only an "in" mark; use clip end.
                    try:
                        existing = clip.GetMarkInOut() or {}
                        video = existing.get("video") or {}
                        out_frame = int(video.get("out") or (in_frame + 1))
                    except Exception:
                        out_frame = in_frame + 1
                if out_frame <= in_frame:
                    out_frame = in_frame + 1
                try:
                    mark_ok = bool(clip.SetMarkInOut(in_frame, out_frame, p.get("mark_type") or "all"))
                    mark_set = {
                        "applied": mark_ok,
                        "in_frame": in_frame,
                        "out_frame": out_frame,
                        "fps_used": fps,
                        "mark_in_seconds": mark_in_s,
                        "mark_out_seconds": mark_out_s,
                    }
                except Exception as exc:
                    mark_set = {"applied": False, "error": str(exc)}

        # Navigate the bin to the clip's folder so the clip is visible to select.
        if parent is not None:
            try:
                mp.SetCurrentFolder(parent)
            except Exception:
                pass  # not fatal; SetSelectedClip below may still work
        select_ok = bool(mp.SetSelectedClip(clip))

        # Bring Resolve to the foreground so the editor doesn't have to
        # alt-tab. Default on; pass focus_app=false to suppress.
        focus_app = p.get("focus_app", p.get("focusApp", True))
        focus_result: Optional[Dict[str, Any]] = None
        if focus_app:
            focus_result = _activate_resolve_window()

        # Jump the source viewer playhead to Mark In via Shift+I keystroke.
        # Resolve's scripting API has no direct "set source viewer playhead"
        # call, so we send the keyboard equivalent of "Go to In" once the
        # app is in the foreground. Default on when a mark was set.
        jump_result: Optional[Dict[str, Any]] = None
        wants_jump = p.get("jump_to_mark_in", p.get("jumpToMarkIn", True))
        applied_mark = bool(mark_set and mark_set.get("applied"))
        if wants_jump and applied_mark and focus_result and focus_result.get("activated"):
            jump_result = _send_resolve_keystroke_go_to_mark_in()

        return {
            "success": select_ok,
            "clip_id": clip.GetUniqueId(),
            "clip_name": clip.GetName(),
            "folder_name": parent.GetName() if parent else None,
            "page": page,
            "mark_set": mark_set,
            "focus": focus_result,
            "playhead_jump": jump_result,
            "note": (
                "Clip selected in bin. On Media page the source viewer auto-loads "
                "the selection. On Cut/Edit pages the clip is selected but the "
                "source viewer may not auto-load — call again with page='media' or "
                "double-click in Resolve."
            ) if page != "media" else (
                "Clip selected and auto-loaded in Media page source viewer."
                + (" Mark In/Out set." if mark_set and mark_set.get("applied") else "")
                + (" Resolve activated." if focus_result and focus_result.get("activated") else "")
                + (" Playhead jumped to Mark In." if jump_result and jump_result.get("sent") else "")
            ),
        }

    clip = _find_clip(mp.GetRootFolder(), p.get("clip_id", ""))
    if not clip:
        return _err(f"Clip not found: {p.get('clip_id')}")

    if action == "get_name":
        return {"name": clip.GetName()}
    elif action == "get_metadata":
        return {"metadata": _ser(clip.GetMetadata(p.get("key", "")))}
    elif action == "set_metadata":
        if "metadata" in p:
            ok = bool(clip.SetMetadata(p["metadata"]))
            if ok:
                silent = _verify_writeback(clip, p["metadata"])
                if silent:
                    return silent
            return {"success": ok}
        ok = bool(clip.SetMetadata(p["key"], p["value"]))
        if ok:
            silent = _verify_clip_property_writeback(clip, p["key"], p["value"])
            if silent:
                return silent
        return {"success": ok}
    elif action == "get_third_party_metadata":
        return {"metadata": _ser(clip.GetThirdPartyMetadata(p.get("key", "")))}
    elif action == "set_third_party_metadata":
        return {"success": bool(clip.SetThirdPartyMetadata(p["key"], p["value"]))}
    elif action == "get_media_id":
        return {"media_id": clip.GetMediaId()}
    elif action == "get_clip_property":
        key = p.get("key", "")
        raw = _ser(clip.GetClipProperty(key))
        result = {"properties": raw}
        if key == "" and isinstance(raw, dict) and "Cloud Sync" in raw:
            result["cloud_sync_status"] = cloud_sync_status_label(raw.get("Cloud Sync"))
        elif key == "Cloud Sync":
            result["cloud_sync_status"] = cloud_sync_status_label(raw)
        return result
    elif action == "set_clip_property":
        ok = bool(clip.SetClipProperty(p["key"], p["value"]))
        if ok:
            silent = _verify_clip_property_writeback(clip, p["key"], p["value"])
            if silent:
                return silent
        return {"success": ok}
    elif action == "set_clip_super_scale":
        missing = _requires_method(clip, "SetClipProperty", "21.0")
        if missing:
            return missing
        mode = p.get("mode")
        sharpness = p.get("sharpness")
        noise_reduction = _first_param(p, "noise_reduction", "noiseReduction", default=None)
        if mode not in (1, 2, 3, 4):
            return _err("set_clip_super_scale requires mode in {1,2,3,4} (1=no scaling,2/3/4=2x/3x/4x)")
        if (sharpness is None) != (noise_reduction is None):
            return _err("sharpness and noise_reduction must be provided together")
        if sharpness is not None:
            if mode != 2:
                return _err("sharpness/noise_reduction (2x Enhanced) only apply to mode=2")
            if not (0.0 <= sharpness <= 1.0) or not (0.0 <= noise_reduction <= 1.0):
                return _err("sharpness and noise_reduction must be in [0.0, 1.0]")
            mutate = lambda: clip.SetClipProperty("Super Scale", mode, sharpness, noise_reduction)
        else:
            mutate = lambda: clip.SetClipProperty("Super Scale", mode)
        res = verify_by_readback(
            mutate=mutate,
            observe=lambda: clip.GetClipProperty("Super Scale"),
            compare=lambda before, observed: {"verified": str(observed) == str(mode)},
            label="media_pool_item.set_clip_super_scale",
            intent={"mode": mode, "enhanced": sharpness is not None},
        )
        return {"success": res["success_raw"], "verified": res["verified"], "mode": mode,
                "enhanced": sharpness is not None, "observed": res["observed"]}
    elif action == "get_clip_color":
        return {"color": clip.GetClipColor()}
    elif action == "set_clip_color":
        return {"success": bool(clip.SetClipColor(p["color"]))}
    elif action == "clear_clip_color":
        return {"success": bool(clip.ClearClipColor())}
    elif action == "link_proxy":
        return {"success": bool(clip.LinkProxyMedia(p["proxy_path"]))}
    elif action == "unlink_proxy":
        return {"success": bool(clip.UnlinkProxyMedia())}
    elif action == "replace_clip":
        return {"success": bool(clip.ReplaceClip(p["path"]))}
    elif action == "set_name":
        return {"success": bool(clip.SetName(p["name"]))}
    elif action == "link_full_resolution_media":
        full_res_path = p.get("path") or p.get("full_res_media_path") or p.get("fullResMediaPath")
        if not full_res_path:
            return _err("Provide path or full_res_media_path")
        return {"success": bool(clip.LinkFullResolutionMedia(full_res_path))}
    elif action == "monitor_growing_file":
        return {"success": bool(clip.MonitorGrowingFile())}
    elif action == "replace_clip_preserve_sub_clip":
        replacement_path = p.get("path") or p.get("file_path") or p.get("filePath")
        if not replacement_path:
            return _err("Provide path or file_path")
        return {"success": bool(clip.ReplaceClipPreserveSubClip(replacement_path))}
    elif action == "get_unique_id":
        return {"id": clip.GetUniqueId()}
    elif action == "transcribe_audio":
        usd = _first_param(p, "use_speaker_detection", "useSpeakerDetection")
        if usd is None:
            return _run_maybe_background(
                "media_pool_item.transcribe_audio", p, lambda: {"success": bool(clip.TranscribeAudio())}
            )
        return _run_maybe_background(
            "media_pool_item.transcribe_audio", p, lambda: {"success": bool(clip.TranscribeAudio(bool(usd)))}
        )
    elif action == "clear_transcription":
        return {"success": bool(clip.ClearTranscription())}
    elif action == "get_transcription":
        raw = clip.GetClipProperty("Transcription")
        text = raw if isinstance(raw, str) else ("" if raw is None else str(raw))
        try:
            status = clip.GetClipProperty("Transcription Status")
        except Exception:
            status = None
        return {
            "clip_id": p.get("clip_id"),
            "text": text,
            "truncated": _is_truncated(text),
            "status": status or None,
            "has_transcription": bool(text.strip()),
        }
    elif action == "extract_frames":
        return _extract_clip_frames(clip, p)
    elif action == "perform_audio_classification":
        missing = _requires_method(clip, "PerformAudioClassification", "21.0")
        if missing:
            return missing
        with _ai_ledger_timed("perform_audio_classification", clip_id=p.get("clip_id")) as _rec:
            ok = bool(clip.PerformAudioClassification())
            _rec.success = ok
        return {"success": ok}
    elif action == "clear_audio_classification":
        missing = _requires_method(clip, "ClearAudioClassification", "21.0")
        if missing:
            return missing
        with _ai_ledger_timed("clear_audio_classification", clip_id=p.get("clip_id")) as _rec:
            ok = bool(clip.ClearAudioClassification())
            _rec.success = ok
        return {"success": ok}
    elif action == "analyze_for_intellisearch":
        missing = _requires_method(clip, "AnalyzeForIntellisearch", "21.0")
        if missing:
            return missing
        identify_faces = bool(_first_param(p, "identify_faces", "identifyFaces", default=False))
        is_better_mode = bool(_first_param(p, "is_better_mode", "isBetterMode", default=False))
        with _ai_ledger_timed("analyze_for_intellisearch", clip_id=p.get("clip_id")) as _rec:
            ok = bool(clip.AnalyzeForIntellisearch(identify_faces, is_better_mode))
            _rec.success = ok
        return {"success": ok}
    elif action == "analyze_for_slate":
        missing = _requires_method(clip, "AnalyzeForSlate", "21.0")
        if missing:
            return missing
        marker_color = _first_param(p, "marker_color", "markerColor", default="Blue")
        if marker_color not in _MARKER_COLORS:
            return _err(f"Invalid marker_color {marker_color!r}. Valid colors: {', '.join(_MARKER_COLORS)}")
        with _ai_ledger_timed("analyze_for_slate", clip_id=p.get("clip_id")) as _rec:
            ok = bool(clip.AnalyzeForSlate(marker_color))
            _rec.success = ok
        return {"success": ok}
    elif action == "remove_motion_blur":
        missing = _requires_method(clip, "RemoveMotionBlur", "21.0")
        if missing:
            return missing
        deblur = _first_param(p, "deblur_option", "deblurOption", default=None) or {}
        gate = _ai_governance_gate("remove_motion_blur", p)
        if gate:
            return gate
        if "confirm_token" not in p and "confirmToken" not in p and _confirm_token_required():
            return _issue_confirm_token(
                action="media_pool_item.remove_motion_blur",
                params=p,
                preview={
                    "operation": "media_pool_item.remove_motion_blur",
                    "warning": "Renders a NEW deblurred media file; the source clip is not modified.",
                    "clip": clip.GetName(),
                    "deblur_option": deblur,
                    "governance": _ai_governance_check("remove_motion_blur"),
                },
            )
        blocked = _consume_confirm_token(action="media_pool_item.remove_motion_blur", params=p)
        if blocked:
            return blocked
        with _ai_ledger_timed("remove_motion_blur", clip_id=p.get("clip_id")) as _rec:
            new_clip = clip.RemoveMotionBlur(deblur)
            _rec.success = bool(new_clip)
            if new_clip:
                path, nbytes = _clip_file_size(new_clip)
                _rec.output_path = path
                _rec.output_bytes = nbytes
        if not new_clip:
            return {"success": False}
        return {"success": True, "new": new_clip.GetName(), "new_id": new_clip.GetUniqueId(),
                "output_path": _rec.output_path, "output_bytes": _rec.output_bytes}
    elif action == "get_audio_mapping":
        return {"mapping": clip.GetAudioMapping()}
    elif action == "get_mark_in_out":
        return _ser(clip.GetMarkInOut())
    elif action == "set_mark_in_out":
        err, clean = _validate_params(
            p,
            {"mark_in": {"type": int, "required": True}, "mark_out": {"type": int, "required": True}},
            invariants=[lambda c: f"mark_in ({c['mark_in']}) must be <= mark_out ({c['mark_out']})"
                        if c["mark_in"] > c["mark_out"] else None],
        )
        if err:
            return _err(err)
        return {"success": bool(clip.SetMarkInOut(clean["mark_in"], clean["mark_out"], p.get("type", "all")))}
    elif action == "clear_mark_in_out":
        return {"success": bool(clip.ClearMarkInOut(p.get("type", "all")))}
    return _unknown(action, ["get_name","get_metadata","set_metadata","get_third_party_metadata","set_third_party_metadata","get_media_id","get_clip_property","set_clip_property","set_clip_super_scale","get_clip_color","set_clip_color","clear_clip_color","link_proxy","unlink_proxy","replace_clip","set_name","link_full_resolution_media","monitor_growing_file","replace_clip_preserve_sub_clip","get_unique_id","transcribe_audio","clear_transcription","get_transcription","extract_frames","perform_audio_classification","clear_audio_classification","analyze_for_intellisearch","analyze_for_slate","remove_motion_blur","get_audio_mapping","get_mark_in_out","set_mark_in_out","clear_mark_in_out","open_in_viewer"])

def _compact_structural_diff(diff: Any, *, sample_n: int = 3) -> Any:
    """Trim a compare_usage_snapshots result for the default execute response.

    The full added/removed/moved/trimmed rows (one per timeline item, each with
    media_pool_item_id + track + in/out frames) dominate large tighten
    responses — 226 KB for a 130-segment tighten (issue #84). The counts already
    live in `summary`; keep those plus a small head/tail sample per change kind.
    The full diff is persisted in the executed plan record (edit_engine
    get_plan(plan_id) → plan.execution_summary.structural_diff) and returned
    inline when the caller passes include_details=true.
    """
    if not isinstance(diff, dict):
        return diff
    # An error stand-in (diff failed) or an already-compact payload: pass through.
    if "summary" not in diff:
        return diff
    sample: Dict[str, Any] = {}
    omitted = 0
    for kind in ("added", "removed", "moved", "trimmed"):
        rows = diff.get(kind)
        if not isinstance(rows, list) or not rows:
            continue
        if len(rows) <= sample_n:
            sample[kind] = list(rows)
            continue
        # Head sample + final row so the caller sees both ends of the change set.
        sample[kind] = list(rows[: sample_n - 1]) + [rows[-1]]
        omitted += len(rows) - sample_n
    return {
        "summary": diff.get("summary"),
        "sample": sample,
        "truncated": True,
        "omitted_rows": omitted,
        "detail_hint": (
            "Full per-item diff persisted in the plan record — retrieve via "
            "edit_engine get_plan(plan_id) → plan.execution_summary.structural_diff, "
            "or re-run with include_details=true to inline it."
        ),
    }

def _find_clip_by_file_path(folder, path: str):
    """Media pool clip whose File Path matches (exact, then basename)."""
    target = str(path)
    base = os.path.basename(target)
    by_name = None
    stack = [folder]
    while stack:
        f = stack.pop()
        for clip in (f.GetClipList() or []):
            try:
                clip_path = str(clip.GetClipProperty("File Path") or "")
            except Exception:
                clip_path = ""
            if clip_path == target:
                return clip
            if by_name is None and os.path.basename(clip_path) == base:
                by_name = clip
        stack.extend(f.GetSubFolderList() or [])
    return by_name


